window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q08"]=window.__LIBQ["tien-nghich"]["q08"]||{};window.__LIBQ["tien-nghich"]["q08"]["map"]={"updatedAt":"2026-07-09","count":247,"nodes":[{"id":"chu-tuoc","name":"Chu Tước","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Quê hương Vương Lâm nghĩ tới khi an táng Tôn Thái. Hắn tự hỏi nếu mình chết, liệu có ai đưa tro cốt về Chu Tước hay không.","detail":"Trong cảm khái trước mộ Tôn Thái, Vương Lâm liên tưởng tới Chu Tước như cố hương của chính mình. Địa danh này gắn với nỗi lo chết tha hương và không thể trở về quê nhà của tu sĩ.","theLucLienQuan":[],"nguon":["@c0888"]},{"id":"phia-tay-va-phia-bac-cua-lien-minh","name":"Phía Tây và phía Bắc của Liên Minh","cn":"","capDo":"vuc","parentId":"lien-minh-tu-chan-dia-vuc","blurb":"Khu vực trở thành vùng đình chiến của tu sĩ La Thiên sau chiến tranh. Đây là tuyến được trấn giữ để đề phòng Liên Minh Tu Chân tấn công tiếp.","detail":"Sau đại chiến, phía Tây và phía Bắc Liên Minh trở thành khu đình chiến có tu sĩ La Thiên trú đóng. Liệt Vân Tử cùng mười ba huyết cầu La Phù trấn giữ khu vực này.","theLucLienQuan":["La Thiên","Liên Minh Tu Chân"],"nguon":["@c0888"]},{"id":"tu-chan-tinh-gan-chien-truong-cu","name":"Tu chân tinh gần chiến trường cũ","cn":"","capDo":"tinh-cau","parentId":"phia-tay-va-phia-bac-cua-lien-minh","blurb":"Hành tinh gần chiến trường trước đây nhất và được bảo toàn trong chiến tranh. Liệt Vân Tử cùng Hứa Đình ở lại đây để trấn giữ.","detail":"Tu chân tinh này nằm gần chiến trường cũ và không bị hủy trong chiến tranh. Trên đó, Liệt Vân Tử khoanh chân tại đỉnh núi, dùng mười ba huyết cầu La Phù tăng cảm ứng, còn Hứa Đình cũng xuất hiện bên cạnh lão.","theLucLienQuan":["La Thiên"],"nguon":["@c0888"]},{"id":"vung-tinh-khong-vo-tan-trong-y-canh","name":"Vùng tinh không vô tận trong ý cảnh","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian ý cảnh Vương Lâm nhìn thấy sau khi mở trọn Chiến Tự Thiếp Đệ Nhị Phúc. Tại đây, lão giả áo trắng ngồi khoanh chân và vẽ chữ Chiến lên hư không.","detail":"Sau khi bức tranh chữ Chiến được mở hoàn toàn, Vương Lâm chìm vào một vùng tinh không vô tận trong ý cảnh. Không gian này là nơi hiện ra lời truyền thừa của lão giả áo trắng về Không Chi và Chiến Tự Lục Thiếp.","theLucLienQuan":["Chiến gia"],"nguon":["@c0889"]},{"id":"tu-chan-tinh-cua-chien-gia","name":"Tu chân tinh của Chiến Gia","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tu chân tinh nơi Vương Lâm gặp Liệt Vân Tử và được đưa xem Đệ Tam Phúc Chiến Tự Thiếp. Sau khi từ chối mở tranh, Vương Lâm rời khỏi nơi này bay vào tinh không.","detail":"Đây là địa điểm diễn ra cuộc đối thoại giữa Liệt Vân Tử và Vương Lâm xoay quanh bí mật Đệ Tam Phúc. Sau khi nhận ra nguy hiểm của bức tranh và không chấp nhận mở ra, Vương Lâm rời tu chân tinh, tự phân tích lợi hại của chuyến đi.","theLucLienQuan":["Chiến Gia","La Thiên"],"nguon":["@c0890"]},{"id":"hon-da-khong-lo-lo-lung-trong-tinh-khong","name":"Hòn đá khổng lồ lơ lửng trong tinh không","cn":"","capDo":"khac","parentId":null,"blurb":"Hòn đá lớn trong tinh không nơi Vương Lâm khoanh chân chờ Thanh Thủy. Từ đây hai người chuẩn bị tiến vào Sát Vực Giới.","detail":"Sau khi rời tu chân tinh của Chiến Gia, Vương Lâm tới một hòn đá khổng lồ lơ lửng trong tinh không và chờ vài ngày. Thanh Thủy sau đó xuất hiện với hơn trăm đầu lâu tu sĩ Sát Vực Giới, mở đầu việc thi triển U Minh Dẫn Lộ.","theLucLienQuan":[],"nguon":["@c0890"]},{"id":"that-cap-tu-chan-tinh","name":"Thất cấp tu chân tinh","cn":"","capDo":"khac","parentId":"lien-minh-tinh-vuc","blurb":"Loại tu chân tinh cấp cao trong Liên Minh Tinh Vực. Tu sĩ đạt trình độ nhất định tại đây thường không cam tâm giao mệnh hồn, từ đó thành đối tượng bị Sát Vực Giới xử lý.","detail":"Chương này dùng Thất cấp tu chân tinh để giải thích vai trò đối ngoại của Sát Vực Giới. Khi tu sĩ ở cấp tinh cầu này không chịu bị nắm mệnh hồn, Sát Vực Giới thường được phái đi giải quyết bằng thủ đoạn giết chóc và ẩn nấp.","theLucLienQuan":["Sát Vực Giới","Tu Chân Liên Minh"],"nguon":["@c0891"]},{"id":"toa-thap-trung-tam-sat-vuc-gioi","name":"Tòa tháp trung tâm Sát Vực Giới","cn":"","capDo":"khac","parentId":"sat-vuc-gioi-map","blurb":"Tòa tháp trung tâm trong Sát Vực Giới, nơi lão già hắc y phó giới chủ khoanh chân tọa trấn. Thanh Thủy áp sát, phá tháp và kéo lão khỏi khe nứt hư vô bên trong.","detail":"Tòa tháp là vị trí trọng yếu trong Sát Vực Giới ở chương này. Khi Thanh Thủy đánh tới, phó giới chủ trong tháp mở khe nứt hư vô tìm đường rời đi, nhưng bị Đóng Băng Thiên Địa phong tỏa và bị Thanh Thủy phá tháp lôi ra.","theLucLienQuan":["Sát Vực Giới"],"nguon":["@c0891"]},{"id":"khe-nut-hu-vo-trong-thap-sat-vuc-gioi","name":"Khe nứt hư vô trong tháp Sát Vực Giới","cn":"","capDo":"khac","parentId":"toa-thap-trung-tam-sat-vuc-gioi","blurb":"Khe nứt không gian do phó giới chủ Sát Vực Giới mở ra trong tháp trung tâm để thoát thân. Đường này bị lam quang Đóng Băng Thiên Địa của Thanh Thủy phong tỏa.","detail":"Khe nứt hư vô là lối thoát mà lão già hắc y phó giới chủ lựa chọn ngay khi nhận ra Thanh Thủy đánh tới. Thanh Thủy dùng hàn khí và lam quang bao phủ Sát Vực Giới, khóa khe nứt trước khi lão hoàn toàn rời đi.","theLucLienQuan":["Sát Vực Giới"],"nguon":["@c0891"]},{"id":"sat-vuc-gioi","name":"Sát Vực giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Chiến trường chính của chương 893. Đây là nơi Vương Lâm đoạt kiếm, Huyễn Hư Tử và Thần Ma Tử lần lượt lộ diện, đồng thời xảy ra giao phong giữa Cổ Thần lực và thần thông Tịnh Niết.","detail":"Sát Vực giới trong chương 893 là nơi các tu sĩ bản giới bị Tát Đậu Thành Binh và lôi đình kiềm chế, còn Vương Lâm tranh đoạt phi kiếm giữa chiến trường. Huyễn Hư Tử từ ánh sáng đỏ sậm trên mặt đất lộ diện, sau đó Thần Ma Tử cũng xuất hiện để đánh lén, khiến nơi này trở thành điểm va chạm của nhiều tu sĩ cấp cao.","theLucLienQuan":["Tu sĩ Sát Vực giới","Liên Minh"],"nguon":["@c0893"]},{"id":"tu-chan-tinh-cua-than-ma-tu","name":"Tu chân tinh của Thần Ma Tử","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tu chân tinh gắn với quá khứ của Thần Ma Tử. Tại đây hắn từng cẩn thận giết nhiều tu sĩ để cướp đan dược pháp bảo mà không bị phát hiện.","detail":"Chương 893 nhắc lại quá khứ Thần Ma Tử ở tu chân tinh của mình, nơi hắn dùng nhiều ngàn năm âm thầm giết vô số tu sĩ để cướp đoạt đan dược pháp bảo. Địa danh này làm nổi bật tính cách cẩn thận và âm hiểm của hắn.","theLucLienQuan":["Sát Vực giới"],"nguon":["@c0893"]},{"id":"may-tim-tren-bau-troi","name":"Mây tím trên bầu trời","cn":"","capDo":"khac","parentId":"sat-vuc-gioi","blurb":"Khu vực phát sinh biến cố cuối chương 893. Từ mây tím truyền ra tiếng hừ thảm rồi bảy bóng dáng màu tím rơi xuống.","detail":"Ngay lúc Thần Ma Tử chuẩn bị ra tay với Vương Lâm, mây tím trên bầu trời cuồn cuộn và truyền ra tiếng hừ thảm. Sau đó bảy bóng dáng màu tím rơi ầm xuống dưới, tan vỡ dần khi gần mặt đất và cuối cùng chỉ còn lại một bóng.","theLucLienQuan":[],"nguon":["@c0893"]},{"id":"hon-hai-bi-mat-trong-lien-minh-tinh-vuc","name":"Hồn hải bí mật trong Liên Minh Tinh Vực","cn":"","capDo":"khac","parentId":"lien-minh-tinh-vuc","blurb":"Hồn hải bí mật là khu vực không người ngoài biết trong Liên Minh Tinh Vực. Nơi đây có đại lục lơ lửng và lầu các màu đen, là chỗ nguyên thần thanh niên áo lam trọng thương trở về.","detail":"Sau khi bị công kích qua lốc xoáy, nguyên thần thanh niên áo lam xuất hiện tại hồn hải bí mật trong Liên Minh Tinh Vực. Từ lầu các màu đen trên đại lục lơ lửng, lão nhân âm trầm bước ra cứu cháu mình, cho thấy nơi này là điểm trú ẩn quan trọng của thế lực phía sau thanh niên áo lam.","theLucLienQuan":["Liên Minh Tinh Vực"],"nguon":["@c0897"]},{"id":"trieu-tich-chi-dia","name":"Triều Tịch Chi Địa","cn":"","capDo":"khac","parentId":null,"blurb":"Triều Tịch Chi Địa được nhắc như nơi có tiên phủ gắn với lệnh bài tiên phủ. Danh tiếng năm xưa của Vương Lâm tại đây khiến các tu sĩ đại thần thông của Thiên Vận tinh chú ý.","detail":"Trong chương này, Triều Tịch Chi Địa được gắn với tuyến tiên phủ và lệnh bài tiên phủ mà nhiều lão quái muốn đoạt. Phấn y tiên tử cũng tò mò về Vương Lâm vì hắn từng danh chấn Triều Tịch, khiến các tu sĩ đại thần thông của Thiên Vận tinh chú ý.","theLucLienQuan":[],"nguon":["@c0897"]},{"id":"thien-van-tong-dia-diem","name":"Thiên Vận Tông","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Sơn môn và quảng trường nơi mọi người chờ Vương Lâm trở về trong chương 898.","detail":"Tại Thiên Vận Tông, Vương Lâm xuất hiện trước các tu sĩ và lão quái, hành lễ với Thiên Vận Tử, bị truy hỏi về Yêu Linh Chi Địa và lệnh bài tiên phủ. Đây cũng là nơi Thiên Vận Tử ngăn Lăng Thiên Hậu ra tay với đệ tử của mình.","theLucLienQuan":["Thiên Vận Tông","Đại La Kiếm Tông"],"nguon":["@c0898"]},{"id":"yeu-linh-chi-dia","name":"Yêu Linh Chi Địa","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Địa điểm quá khứ liên quan trực tiếp tới việc Vương Lâm bị chất vấn về giết người, bỏ chạy và lấy lệnh bài tiên phủ.","detail":"Trong chương 898, Yêu Linh Chi Địa được nhắc là nơi Vương Lâm từng giết người Đại La Kiếm Tông, nhốt nữ nhân của Huyết Tổ, trốn vào lốc xoáy và chiếm được lệnh bài tiên phủ. Những chuyện cũ này khiến các lão quái gây áp lực với hắn khi hắn trở lại Thiên Vận Tông.","theLucLienQuan":["Đại La Kiếm Tông"],"nguon":["@c0898"]},{"id":"thien-van-tong-quang-truong","name":"Thiên Vận Tông quảng trường","cn":"","capDo":"khac","parentId":"thien-van-tong-dia-diem","blurb":"Thiên Vận Tông quảng trường là nơi mọi người tản đi sau trận giao phong, chỉ còn Vương Lâm và Thiên Vận Tử đối thoại riêng. Tại đây Vương Lâm nói rõ mục tiêu muốn vào Yêu Linh Chi Địa.","detail":"Sau khi Lăng Thiên Hậu, các lão quái và đệ tử rời đi, trên quảng trường Thiên Vận Tông chỉ còn Vương Lâm và Thiên Vận Tử. Hai người im lặng một lúc rồi trao đổi về tư cách vào Yêu Linh Chi Địa, thân phận chính phẩm Lôi Tiên La Thiên và danh sách Chu Tước.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0899"]},{"id":"mong-tinh","name":"Mộng Tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Mộng Tinh là địa danh gắn với Kỳ Mộng Đàm. Ông mời Vương Lâm tới Mộng Tinh sau khi chứng kiến thực lực của hắn.","detail":"Kỳ Mộng Đàm tự xưng và nói nếu Vương Lâm có thời gian thì xin mời tới Mộng Tinh của ông chơi. Lời mời này biểu thị thái độ muốn kết giao sau trận Vương Lâm đối đầu Lăng Thiên Hậu.","theLucLienQuan":["Mộng Tinh"],"nguon":["@c0899"]},{"id":"tu-ha-tinh","name":"Tử Hà Tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tử Hà Tinh là nơi mỹ phụ luyện khí mời Vương Lâm tới để bàn chuyện phi kiếm sát khí khó khống chế. Địa danh này gắn với năng lực luyện khí của bà và nhóm nữ tu đi cùng.","detail":"Sau khi quan sát phi kiếm của Vương Lâm, mỹ phụ luyện khí nhận ra sát khí của chúng quá nặng, khó khống chế. Khi rời khỏi Thiên Vận Tông, bà mời Vương Lâm tới Tử Hà Tinh nếu có thời gian.","theLucLienQuan":["Tử Hà Tinh"],"nguon":["@c0899"]},{"id":"dong-phu-trong-yeu-linh-chi-dia","name":"Động phủ trong Yêu Linh Chi Địa","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Động phủ mà Thiên Vận Tử dự định tiến vào khi Yêu Linh Chi Địa mở ra. Hắn còn muốn mời thêm một số hảo hữu cùng đi vì lần này liên quan chuyện trọng yếu.","detail":"Trong lời an bài với Vương Lâm, Thiên Vận Tử nói việc mở Yêu Linh Chi Địa còn cần chuẩn bị và sau khi mở sẽ vào một động phủ. Địa điểm này là mục tiêu của chuyến đi sắp tới, không chỉ có Vương Lâm mà còn có các hảo hữu do Thiên Vận Tử mời thêm.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0900"]},{"id":"tu-lam-cac","name":"Tử Lâm Các","cn":"","capDo":"khac","parentId":"tu-phong","blurb":"Lầu các cũ của Vương Lâm tại Tử hệ Thiên Vận Tông. Nơi này vẫn được giữ lại cho hắn, bên trong phủ bụi nhưng bài trí không đổi sau nhiều trăm năm.","detail":"Thiên Vận Tử nhắc Tử Lâm Các Thủy vẫn còn giữ cho Vương Lâm. Khi trở lại, Vương Lâm thấy lầu các phủ đầy bụi, đèn dầu đã cạn nhưng cách bài trí vẫn như năm xưa; chính tại đây, hắn thắp lại ngọn đèn dầu và ngộ ra cách giải thích về sự biến hóa khó lường của Thiên Vận Tử.","theLucLienQuan":["Thiên Vận Tông","Tử hệ Thiên Vận Tông"],"nguon":["@c0900"]},{"id":"tu-phong","name":"Tử Phong","cn":"","capDo":"khac","parentId":"thien-van-tong-dia-diem","blurb":"Ngọn núi của Tử hệ Thiên Vận Tông, nơi đặt Tử Lâm Các. Vương Lâm trở lại đây sau nhiều trăm năm xa cách.","detail":"Tử Phong có tử quang và mây mù, là nơi cư ngụ gắn với Tử hệ. Khi Vương Lâm trở lại, cảnh núi và lầu các cũ khiến hắn nhớ thời mới rời Chu Tước Tinh tới Thiên Vận Tông.","theLucLienQuan":["Thiên Vận Tông","Tử hệ Thiên Vận Tông"],"nguon":["@c0900"]},{"id":"con-duong-son-dao-len-tu-he","name":"Con đường sơn đạo lên Tử hệ","cn":"","capDo":"khac","parentId":"thien-van-tong-dia-diem","blurb":"Con đường từ quảng trường dẫn lên ngọn núi Tử hệ. Vương Lâm đi lại con đường quen thuộc này sau nhiều trăm năm.","detail":"Sơn đạo có bậc thang, đường mòn âm u, núi đá, rừng cây, gió chiều và tiếng nước. Đây là tuyến đường Vương Lâm từng đi qua năm xưa và nay trở lại trong tâm trạng cảm khái vì cảnh vật dường như không thay đổi.","theLucLienQuan":["Thiên Vận Tông","Tử hệ Thiên Vận Tông"],"nguon":["@c0900"]},{"id":"quy-nhan-phuong-thi","name":"Quỷ Nhãn phường thị","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm giao dịch sắp mở lại sau bảy ngày. Nơi này từng nổi danh vì bán đấu giá tiên thuật đầy đủ và có khu giao dịch tự do bên ngoài.","detail":"Quỷ Nhãn phường thị được Lý sư huynh và sư muội nhắc tới trên đường Tử hệ. Phường thị có khu đấu giá cần tư cách, đồng thời bên ngoài còn có phố giao dịch tự do, nơi Lý sư huynh cho rằng đệ tử như họ vẫn có thể tìm cơ hội.","theLucLienQuan":[],"nguon":["@c0900"]},{"id":"phong-tren-tu-phong","name":"Phòng trên Tử Phong","cn":"","capDo":"khac","parentId":"tu-phong","blurb":"Căn phòng trên Tử Phong nơi Vương Lâm quan sát ánh nến và suy ngộ quy tắc.","detail":"Đây là không gian khép kín nơi Vương Lâm đóng cửa cắt gió, nhìn ánh nến lay động rồi từng bước lần tới Hỏa chi quy tắc và manh mối về căn nguyên. Sau một đêm điều tức trong phòng, hắn nghe tiếng người ngoài lầu gọi lão thất.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0901"]},{"id":"thien-van-tong-that-phong","name":"Thiên Vận Tông Thất phong","cn":"","capDo":"khac","parentId":"thien-van-tong-dia-diem","blurb":"Bảy ngọn phong của Thiên Vận Tông hiện ra trên đường Vương Lâm xuống Tử Phong. Đây là không gian sinh hoạt chính của các hệ trong tông, người qua lại đông đảo vào giữa trưa.","detail":"Trong chương 903, khi Vương Lâm rời phòng xuống núi, từ Tử Phong có thể nhìn thấy cảnh người tới người lui trên bảy ngọn phong của Thiên Vận Tông. Khung cảnh này đối lập với sự hiu quạnh và địa vị thấp của Tử hệ nhất mạch.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0903"]},{"id":"phuong-thi","name":"Phường thị","cn":"","capDo":"khac","parentId":null,"blurb":"Điểm đến mà Bạch Vi hẹn Vương Lâm cùng tới. Cuối chương, nàng tế phi kiếm dẫn đường để rời Tử Phong đi về phía phường thị.","detail":"Phường thị được nhắc như nơi Bạch Vi đã hẹn đưa Vương Lâm tới. Sau khi gặp nhau dưới chân Tử Phong, Bạch Vi tế phi kiếm bay đi trước dẫn đường, còn Vương Lâm theo sau.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0903"]},{"id":"quy-nhan-thanh-map","name":"Quỷ Nhãn Thành","cn":"","capDo":"thanh","parentId":"thien-van-tinh","blurb":"Thành trì hình tròn trên Thiên Vận Tinh, nơi sắp diễn ra đấu giá và giao dịch tự do; địa điểm xung đột thần thức giữa Vương Lâm và Trần Đạo Tam Tử.","detail":"Quỷ Nhãn Thành là thành trì hình tròn nổi danh vì từng bán đấu giá một bộ tiên thuật đầy đủ. Mỗi tháng mở thành có khu đấu giá cùng các khu tự do giao dịch, có cấm chế và lực lượng bảo an mạnh. Vương Lâm phá cấm chế thành khi bị Trần Đạo Tam Tử vây ép.","theLucLienQuan":["Quỷ Nhãn Thành","Trần Đạo Tam Tử"],"nguon":["@c0904"]},{"id":"thien-van-tong-sau-nui","name":"Thiên Vận Tông sau núi","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Nơi có hoa Bạch Dương Mộc suốt đời không nở, từng nở hoa màu đen trong ba khắc rồi chết hóa thành sương mù.","detail":"Sau núi Thiên Vận Tông có hoa Bạch Dương Mộc vốn suốt đời không nở. Bạch Vi kể rằng nó từng bất ngờ nở hoa màu đen trong ba khắc rồi chết hóa thành sương mù, một dị biến chưa được giải thích.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0904"]},{"id":"khu-dau-gia-quy-nhan-thanh","name":"Khu đấu giá Quỷ Nhãn Thành","cn":"","capDo":"khac","parentId":"quy-nhan-thanh-map","blurb":"Khu vực khiến Quỷ Nhãn Thành nổi danh vì giao dịch tiên thuật, bên cạnh các khu tự do giao dịch trong đợt mở thành một tháng.","detail":"Trong một tháng mở thành của Quỷ Nhãn Thành, ngoài khu đấu giá tiên thuật làm nên danh tiếng thành còn có các khu tự do giao dịch cho tu sĩ.","theLucLienQuan":["Quỷ Nhãn Thành"],"nguon":["@c0904"]},{"id":"kien-truc-hoa-le-trong-quy-nhan-thanh","name":"Kiến trúc hoa lệ trong Quỷ Nhãn thành","capDo":"khac","parentId":"quy-nhan-thanh-map","blurb":"Khu kiến trúc hoa lệ nơi Trần Đạo Tam Tử có các gian phòng riêng trong Quỷ Nhãn thành.","detail":"Nơi ba huynh đệ Trần Đạo Tam Tử có các gian phòng riêng. Người đàn ông trung niên và Nhất Trần Tử đều bị phản phệ thần thức ngay tại đây khi dò xét Vương Lâm.","theLucLienQuan":["Trần Đạo Tam Tử","Quỷ Nhãn Thành"],"nguon":["@c0905"]},{"id":"toa-lau-cac-bon-tang-phia-dong-quy-nhan-thanh","name":"Tòa lầu các bốn tầng phía đông thành","capDo":"khac","parentId":"quy-nhan-thanh-map","blurb":"Nơi tạm cư của ba huynh đệ Trần Đạo Tam Tử tại Quỷ Nhãn thành, cũng là chỗ ở sắp xếp cho Vương Lâm.","detail":"Tòa lầu các bốn tầng nằm ở phía đông Quỷ Nhãn thành, có đại viện, giả sơn, sông suối nhỏ và khí trong lành. Vương Lâm chọn một gian phòng nhỏ ở tầng hai để tĩnh tọa suy xét.","theLucLienQuan":["Trần Đạo Tam Tử"],"nguon":["@c0905"]},{"id":"dai-vien","name":"Đại viện","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Đại viện là nơi Vương Lâm lưu trú trước khi được Nhất Trần Tử mời ra gặp. Phía bắc đại viện có đình hóng mát dùng làm nơi tiếp khách.","detail":"Từ phòng trong đại viện, Vương Lâm mở cửa gặp Nhất Trần Tử đứng ngoài mỉm cười ôm quyền. Sau lời mời, hắn cùng Nhất Trần Tử đi tới đình hóng mát phía bắc đại viện, nơi Trần Đạo Tam Tử chuẩn bị tiếp đãi.","theLucLienQuan":["Trần Đạo Tam Tử"],"nguon":["@c0906"]},{"id":"dinh-hong-mat-phia-bac-dai-vien","name":"Đình hóng mát phía bắc đại viện","cn":"","capDo":"khac","parentId":"dai-vien","blurb":"Đình hóng mát phía bắc đại viện là nơi Trần Đạo Tam Tử tiếp Vương Lâm. Đình được làm bằng tiên ngọc, có tụ linh trận và cảnh sông nước thanh nhàn.","detail":"Trong đình có lão nhân áo xanh, người đàn ông trung niên áo tím và Linh Nhi chờ sẵn. Tại đây Nhất Trần Tử giới thiệu Linh Nhi, Liễu Nguyệt Long và Trận Tinh Hàn với Vương Lâm, Vương Lâm tặng vật cho Linh Nhi, nhận Thiên Minh Thạch và cùng ba người luận đạo tới đêm.","theLucLienQuan":["Trần Đạo Tam Tử"],"nguon":["@c0906"]},{"id":"phong-bach-vi","name":"Phòng Bạch Vi","cn":"","capDo":"khac","parentId":"quy-nhan-thanh-map","blurb":"Nơi Vương Lâm tới kiểm tra sau khi hiểu ra mật ngữ của Bạch Vi.","detail":"Trong phòng có lớp cấm chế thần thức mỏng nhưng phản chấn cực mạnh. Sau khi Vương Lâm phá cấm chế, bên trong không còn bóng người, cho thấy Bạch Vi đã biến mất.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0907"]},{"id":"thung-lung-phia-tay-quy-nhan-thanh","name":"Thung lũng phía tây Quỷ Nhãn thành","cn":"","capDo":"khac","parentId":"quy-nhan-thanh-map","blurb":"Thung lũng cách Quỷ Nhãn thành mấy ngàn dặm về phía tây, nơi Bạch Vi hiện thân.","detail":"Thung lũng bị cấm chế che giấu, bên trong khô vàng và âm khí tràn ngập. Vương Lâm nhờ Hoán Vũ phát hiện nơi này, rồi nghe giọng nam hùng hậu của Bạch Vi vang ra từ trong cấm chế.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0907"]},{"id":"phia-bac-chien-truong-la-thien-lien-minh","name":"Phía bắc chiến trường La Thiên — Liên Minh","cn":"","capDo":"khac","parentId":"lien-minh-tu-chan-dia-vuc","blurb":"Khu vực chiến sự được Nhất Long Tử nhắc tới trong cuộc rượu.","detail":"Tại phía bắc, La Thiên Tinh Vực tiến công và giao chiến với Tu Chân Liên Minh, khiến phía Liên Minh bại lui theo lời Nhất Long Tử.","theLucLienQuan":["La Thiên Tinh Vực","Tu Chân Liên Minh"],"nguon":["@c0907"]},{"id":"thung-lung-co-cam-che","name":"Thung lũng có cấm chế","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Thung lũng nơi Bạch Nguy gặp Vương Lâm và nói ra bí mật về thân thế âm dương của mình. Cấm chế tại đây là bối cảnh cho cuộc trao đổi trước khi Thiên Vận Tử có thể phát hiện dị thường.","detail":"Trong thung lũng có cấm chế, Bạch Nguy kể cho Vương Lâm về nguồn gốc cực dương, linh hồn muội muội, Âm Dương Song Dục quyết và việc bản thân là thực nghiệm của Thiên Vận Tử. Đây cũng là nơi Bạch Nguy đặt Vương Lâm trước lựa chọn nhận tia chí dương hay không.","theLucLienQuan":["Thiên Vận Tông","Tử hệ"],"nguon":["@c0908"]},{"id":"pham-tran-thien-van-tinh","name":"Phàm trần Thiên Vận Tinh","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Khu phàm trần trên Thiên Vận Tinh nơi gia đình phú quý của Bạch Nguy sinh sống. Đây là điểm khởi đầu cho thân thế cực dương, cực âm của hắn.","detail":"Bạch Nguy kể mình sinh trong một gia đình phú quý ở phàm trần Thiên Vận Tinh. Ngày hắn ra đời là ngày cực dương hiếm thấy, đồng thời cũng là khởi nguyên của biến cố khiến muội muội song sinh tiêu tán thân thể và linh hồn dung nhập vào hắn.","theLucLienQuan":[],"nguon":["@c0908"]},{"id":"thien-van-tong-ngon-nui-hinh-tam-xoa-kich","name":"Thiên Vận Tông ngọn núi hình tam xoa kích","cn":"","capDo":"khac","parentId":"thien-van-tong-dia-diem","blurb":"Ngọn núi kỳ dị trong Thiên Vận Tông, nơi Thiên Vận Tử khoanh chân tọa định và ra tay sau giờ Mão.","detail":"Ngọn núi có hình như tam xoa kích, bao phủ tiên khí và hào quang bảy màu như tiên cảnh. Tại đỉnh chính giữa, Thiên Vận Tử mở mắt, nhìn về Quỷ Nhãn thành rồi thi triển Nhất Chỉ Soán Thiên Vận.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0909"]},{"id":"dai-la-tu-chan-tinh","name":"Đại La tu chân tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tu chân tinh gần Thiên Vận Tinh, nơi đặt Đại La Kiếm Tông.","detail":"Đại La tu chân tinh nằm gần Thiên Vận Tinh và vẫn thuộc khu vực thế lực của Thiên Vận Tinh. Đây là nơi Lăng Thiên Hậu lập Đại La Kiếm Tông.","theLucLienQuan":["Đại La Kiếm Tông","Thiên Vận Tinh"],"nguon":["@c0910"]},{"id":"dai-la-kiem-tong-linh-son-thong-thien-cac","name":"Đại La Kiếm Tông linh sơn/thông thiên các","cn":"","capDo":"khac","parentId":"dai-la-tu-chan-tinh","blurb":"Khu linh sơn trong Đại La Kiếm Tông, nơi có 990 thông thiên các hợp thành đại trận.","detail":"Bên trong Đại La Kiếm Tông có vô số lầu các và các tòa thông thiên các vươn lên. Chín trăm chín mươi tòa thông thiên các hợp thành đại trận, trong đó một tháp đặc biệt là nơi Lăng Thiên Hậu tọa trấn cùng bốn thanh nguyên thần kiếm.","theLucLienQuan":["Đại La Kiếm Tông"],"nguon":["@c0910"]},{"id":"lien-minh-tinh-vuc","name":"Liên minh Tinh vực","aliases":["Côn Hư tinh vực"],"cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Tinh vực được Lăng Thiên Hậu nhắc khi nói về vị thế năm xưa của Tứ Thánh Tông.","detail":"Côn Hư tinh vực được nhắc trong lời Lăng Thiên Hậu, gắn với việc Tứ Thánh Tông từng là bá chủ và với danh sách Chu Tước mà Vương Lâm thuộc về.","theLucLienQuan":["Tứ Thánh Tông"],"nguon":["@c0910"]},{"id":"manh-vo-tien-gioi","name":"Mảnh vỡ Tiên Giới","aliases":["Đại lục Tiên Giới"],"cn":"","capDo":"khac","parentId":"tien-gioi","blurb":"Mảnh đại lục Tiên Giới trôi nổi, nơi Vương Lâm đứng khi đối đầu thần thông của Thiên Vận Tử.","detail":"Đây là chiến trường trực tiếp khi Vương Lâm dùng quyền Cổ Thần phá ngón tay khổng lồ. Sau cú va chạm, hắn bị đẩy lùi trên mảnh vỡ, rồi khiến nó thu nhỏ lại và xoay quanh ngoài thân như lớp bảo hộ.","theLucLienQuan":["Vương Lâm","Thiên Vận Tử"],"nguon":["@c0912"]},{"id":"noi-giao-chien-cua-thien-van-tu-ao-xam-va-lang-thien-hau","name":"Nơi giao chiến của Thiên Vận Tử áo xám và Lăng Thiên Hậu","cn":"","capDo":"khac","parentId":null,"blurb":"Khu vực vô danh nơi Thiên Vận Tử áo xám và Lăng Thiên Hậu giao thủ.","detail":"Tại đây trời đất bị bóng tối che phủ, kiếm khí nguyên thần của Lăng Thiên Hậu thắp sáng một khoảng hoàng hôn, rồi Sát Lục khí chân chính và Vũ Tiên Kiếm hình rắn va chạm làm chiến trường bị sát khí bao trùm.","theLucLienQuan":["Thiên Vận Tử - Lăng Thiên Hậu đối nghịch lâu năm"],"nguon":["@c0913"]},{"id":"tinh-khong-ben-ngoai-thien-van-tinh","name":"Tinh không bên ngoài Thiên Vận Tinh","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Khoảng tinh không nơi Vương Lâm, Lăng Thiên Hậu và Thiên Vận Tử áo xám bị gió xoáy bảy màu cuốn tới. Tại đây hai mũi kiếm tiếp tục va chạm dữ dội.","detail":"Sau va chạm giữa kiếm của Lăng Thiên Hậu và thanh kiếm Sát Lục của Thiên Vận Tử áo xám, gió xoáy bảy màu quét ngang, cuốn cả ba người rời khỏi Thiên Vận Tinh ra tinh không. Chương kết thúc khi hai mũi kiếm vẫn tiếp tục va chạm trong không gian bên ngoài tinh cầu.","theLucLienQuan":["Thiên Vận Tông","Kiếm Tôn"],"nguon":["@c0914"]},{"id":"tinh-khong-gan-thien-van-tinh","name":"Tinh không gần Thiên Vận Tinh","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Tinh không gần Thiên Vận Tinh là nơi kiếm Sát Lục và Tiên Kiếm hình rắn va chạm trong chương này. Đây cũng là nơi Thiên Vận tử bảy màu đối chất với Lăng Thiên Hậu.","detail":"Tại vùng tinh không này, hai thanh kiếm giao kích khiến kiếm Sát Lục tan vỡ còn Tiên Kiếm hình rắn nứt thân. Thiên Vận tử áo xám rời về Thiên Vận Tinh, Thiên Vận tử bảy màu hiện thân, và Lăng Thiên Hậu mời Vương Lâm làm trưởng lão Đại La Kiếm Tông để có lý do can dự.","theLucLienQuan":["Thiên Vận Tông","Đại La Kiếm Tông"],"nguon":["@c0915","@c0921"]},{"id":"con-hu-dia-vuc","name":"Côn Hư địa vực","cn":"","capDo":"vuc","parentId":"lien-minh-tinh-vuc","blurb":"Côn Hư địa vực là khu vực tu luyện do tu chân tông Côn Hư kiểm soát. Cứ ba ngàn năm, chỉ ba tu sĩ được mời vào nơi này tu luyện.","detail":"Lăng Thiên Hậu kể rằng tu chân tông Côn Hư phát ba thiệp mời mỗi ba ngàn năm để cho tu sĩ vào Côn Hư địa vực tu luyện. Năm xưa Lăng Thiên Hậu, Thiên Vận tử và một nữ tử như người thường từng cùng vào nơi này.","theLucLienQuan":["Tu chân tông Côn Hư"],"nguon":["@c0915"]},{"id":"tien-phu","name":"Tiên phủ","cn":"","capDo":"khac","parentId":null,"blurb":"Tiên phủ là mục tiêu tương lai mà Lăng Thiên Hậu nói sẽ cùng Vương Lâm tiến vào khi Vực sâu Triều tịch mở ra. Chương này chỉ nhắc tới như một điểm hẹn sắp tới.","detail":"Lăng Thiên Hậu hẹn rằng khi Vực sâu Triều tịch mở ra, hắn sẽ cùng Vương Lâm tiến vào Tiên phủ. Thông tin cụ thể về Tiên phủ chưa được triển khai trong chương này.","theLucLienQuan":[],"nguon":["@c0915"]},{"id":"toa-thap-khong-lo-tren-dai-la-tinh","name":"Tòa tháp khổng lồ trên Đại La tinh","cn":"","capDo":"khac","parentId":"dai-la-tu-chan-tinh","blurb":"Tòa tháp lớn nơi Lăng Thiên Hậu tiến vào sau khi phong Vương Lâm làm trưởng lão.","detail":"Sau khi tuyên bố Vương Lâm là trưởng lão Đại La Kiếm Tông, Lăng Thiên Hậu tiến vào tòa tháp lớn này và từ đó âm thầm quan sát Vương Lâm. Khi ánh sáng vô hình từ biến cố Thiên Nghịch quét tới, thân hình hắn đập nát vách tháp rồi bỏ chạy xuống trung tâm Đại La tinh.","theLucLienQuan":["Đại La Kiếm Tông"],"nguon":["@c0916"]},{"id":"toa-thap-ngoai-ngan-dam","name":"Tòa tháp ngoài ngàn dặm","cn":"","capDo":"khac","parentId":"dai-la-tu-chan-tinh","blurb":"Nơi Vương Lâm tự chọn làm chỗ tạm trú trên Đại La tinh.","detail":"Sau khi hỏi Chu Tú về nơi ở của trưởng lão, Vương Lâm tự chọn một tòa tháp cách xa ngàn dặm. Hắn không vào trong tháp mà ngồi bên ngoài, bố trí Đại Phiến Cấm rồi bắt đầu xử lý tia cực dương.","theLucLienQuan":["Đại La Kiếm Tông"],"nguon":["@c0916"]},{"id":"dinh-tien-son-giong-mui-chia-ba","name":"Đỉnh Tiên Sơn giống mũi chĩa ba","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Vị trí Thiên Vận tử ngồi quan sát Vương Lâm và thi triển thần thông.","detail":"Trên Thiên Vận Tinh, Thiên Vận tử khoanh chân ngồi tại đỉnh Tiên Sơn có hình như mũi chĩa ba. Từ nơi này hắn mở mắt nhìn xuyên khoảng cách, quan sát Vương Lâm nuốt cực dương và thi triển nhiều thần thông chống bàn tay hư vô.","theLucLienQuan":["Thiên Vận tông"],"nguon":["@c0916"]},{"id":"toa-thap-cao-tren-dai-la-kiem-tong","name":"Tòa tháp cao trên Đại La Kiếm Tông","cn":"","capDo":"khac","parentId":"dai-la-kiem-tong","blurb":"Tòa tháp cao trên Đại La Kiếm Tông là nơi Vương Lâm khoanh chân bên ngoài khi Thiên Nghịch thu hồi cực dương. Tại đây, thân thể, nguyên lực và nguyên thần của hắn biến đổi trong mười ngày.","detail":"Vương Lâm ngồi khoanh chân bên ngoài tòa tháp cao này khi hạt châu Thiên Nghịch phóng hai đạo hào quang rồi thu hồi. Hào quang ấm áp bao phủ khiến nguyên lực, nguyên thần Thái Cổ Lôi Long và thân thể Cổ Thần của hắn đồng thời biến đổi, đồng thời tạo khí tức cực nóng trong phạm vi trăm trượng.","theLucLienQuan":["Đại La Kiếm Tông"],"nguon":["@c0918"]},{"id":"khong-gian-hu-vo-cua-thien-nghich","name":"Không gian hư vô của Thiên Nghịch","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian hư vô của Thiên Nghịch là nơi thần thức Vương Lâm bị cuốn vào sau khi lực bổn nguyên mở hạt châu. Bên trong có cánh cửa lớn mà hắn từng nhìn thấy năm xưa.","detail":"Sau khi con mắt thứ ba phóng lực bổn nguyên vào Thiên Nghịch, thần thức Vương Lâm tiến vào không gian hư vô này. Cánh cửa lớn trong đó mở ra khe hở, lực xung kích khiến hắn suýt mê lạc, nhưng cực dương giúp hắn tỉnh lại và bước vào khe cửa.","theLucLienQuan":[],"nguon":["@c0918"]},{"id":"tinh-cau-hoang-da-bo-di","name":"Tinh cầu hoang dã bỏ đi","cn":"","capDo":"tinh-cau","parentId":"tinh-khong","blurb":"Tinh cầu hoang dã hình trăng lưỡi liềm, không có linh lực và đầy tử khí.","detail":"Vương Lâm tới tinh cầu này sau khi rời Đại La tinh. Tinh cầu có tầng cương phong yếu, mặt đất đầy khe nứt và tử khí, là nơi Đồng tử đầu to cùng Lôi Cát được an bài chờ hắn.","theLucLienQuan":[],"nguon":["@c0919"]},{"id":"thuy-linh-tinh","name":"Thủy Linh tinh","cn":"","capDo":"tinh-cau","parentId":"thien-van-tinh","blurb":"Tinh cầu tu chân màu thủy lam, linh khí nồng đậm, thuộc Trần Đạo Tam Tử. Tên tinh cầu được nói là lấy từ tên con gái Nhất Trần tử.","detail":"Nhóm Vương Lâm tới gần Thủy Linh tinh trên đường tìm nơi bế quan. Tại đây, Trần Đạo Tam Tử bay ra kiểm tra khí tức bước thứ hai, rồi Nhất Trần tử mời Vương Lâm ở lại tu luyện để kết giao.","theLucLienQuan":["Trần Đạo Tam Tử"],"nguon":["@c0921","@c1002"]},{"id":"quan-the-cung-dien-phia-dong-thuy-linh-tinh","name":"Quần thể cung điện phía Đông Thủy Linh Tinh","cn":"","capDo":"khac","parentId":"thuy-linh-tinh","blurb":"Quần thể cung điện phía Đông Thủy Linh Tinh là nơi Trần Đạo Tam Tử bố trí cho Vương Lâm tạm cư. Khu vực này nằm trên các đỉnh núi, cổ kính và có linh khí dày đặc nhất tinh cầu.","detail":"Nhất Trần Tử dẫn Vương Lâm đến quần thể cung điện thanh lịch ở phía Đông Thủy Linh Tinh, nói đây là nơi có linh khí dày đặc nhất trên tinh cầu. Vương Lâm chọn nơi này để bế quan, giao Tháp Sơn hộ pháp và yêu cầu những người đi theo không rời quá trăm dặm.","theLucLienQuan":["Trần Đạo Tam Tử"],"nguon":["@c0922"]},{"id":"vu-chi-tien-gioi","name":"Vũ chi tiên giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Vũ chi tiên giới là nơi Thanh Long Thánh Hoàng nói mình gặp nạn trong thần niệm để lại trong Thanh quang thuẫn. Đây là đích đến được nêu trong lời cầu cứu của ông.","detail":"Khi thần niệm trong Thanh quang thuẫn được Vương Lâm tách ra, Thanh Long Thánh Hoàng tự xưng đang gặp nạn tại Vũ chi tiên giới. Ông cầu người nhận tin tới cứu hoặc báo cho Thanh Long Thánh Tông, qua đó mở tuyến liên hệ giữa Thanh quang thuẫn, Tứ Thánh Tông và địa danh này.","theLucLienQuan":["Thanh Long Thánh Tông","Tứ Thánh Tông"],"nguon":["@c0923"]},{"id":"cung-dien-tren-thuy-linh-tinh","name":"Cung điện trên Thủy Linh tinh","cn":"","capDo":"khac","parentId":"thuy-linh-tinh","blurb":"Cung điện là nơi Vương Lâm ban đầu kiểm tra Thanh quang thuẫn và giao phong với ấn ký Thanh Long. Khi khí tức Cổ Thần bùng nổ, hắn phải mang thuẫn rời cung điện ra giữa không trung.","detail":"Trong cung điện, Vương Lâm quan sát thanh quang tiểu thuẫn, phá ấn ký Thanh Long, hút phân thân thanh long bằng con mắt thứ ba và phát hiện khí xoáy chứa thần niệm. Sau khi khí tức Cổ Thần trong thuẫn bộc phát dữ dội, không gian cung điện không còn thích hợp, hắn đưa thuẫn ra không trung Thủy Linh tinh.","theLucLienQuan":[],"nguon":["@c0923"]},{"id":"te-dan-trong-may","name":"Tế đàn trong mây","cn":"","capDo":"khac","parentId":null,"blurb":"Tế đàn trong mây là cảnh giới mộng lặp lại của Linh nhi. Nàng đứng trên tế đàn cao nhất, xung quanh là đám người mặc y phục kỳ dị quỳ tụng gọi Cổ Thần.","detail":"Trong giấc mộng của Linh nhi, tế đàn nằm cao trong mây và gắn với nghi thức tụng niệm cuồng nhiệt. Khi mây trời mở ra, Cổ Thần tám tinh hiện ra, khiến cảnh mộng này trở thành đầu mối quan trọng về mối liên hệ giữa Linh nhi và Cổ Thần.","theLucLienQuan":["Cổ Thần"],"nguon":["@c0925"]},{"id":"tuyet-phong-ngam-binh-minh","name":"Tuyệt phong ngắm bình minh","capDo":"khac","parentId":"thuy-linh-tinh","blurb":"Ngọn núi rất cao trên Thủy Linh Tinh, mây trắng lượn quanh, nhìn ra biển đen vô tận, nơi Linh nhi thường ngắm mặt trời mọc và lặn.","detail":"Một tuyệt phong cao vút trên Thủy Linh Tinh, quanh núi có mây trắng lượn lờ, hướng Đông là ráng đỏ báo bình minh còn phía sau là hải dương đen vô tận. Đây là nơi Linh nhi thường lui tới để ngắm mặt trời mọc và mặt trời lặn; cũng chính tại đây, khi bình minh dâng lên sau lưng Linh nhi, Vương Lâm lần đầu rơi vào một trạng thái cảm ngộ kỳ dị ngắn ngủi.","theLucLienQuan":[],"nguon":["@c0926"]},{"id":"ngon-nui-ben-bien","name":"Ngọn núi bên biển","capDo":"khac","parentId":null,"blurb":"Nơi Vương Lâm khoanh chân cảm ngộ, nhìn ra mặt biển.","detail":"Nơi Vương Lâm ngồi cảm ngộ, đồng thời là trung tâm vùng lực lượng vô hình mười dặm ngăn người khác tiến vào.","theLucLienQuan":[],"nguon":["@c0928"]},{"id":"mat-bien","name":"Mặt biển","capDo":"khac","parentId":"ngon-nui-ben-bien","blurb":"Mặt biển Vương Lâm nhìn chằm chằm trong quá trình cảm ngộ.","detail":"Đối tượng Vương Lâm nhìn chằm chằm khi chờ mặt trời mọc lặn; tiếng sóng cùng cảnh bình minh hoàng hôn gắn với cảm ngộ của hắn.","theLucLienQuan":[],"nguon":["@c0928"]},{"id":"bien-tren-thuy-linh-tinh","name":"Biển trên Thủy Linh tinh","cn":"","capDo":"khac","parentId":"thuy-linh-tinh","blurb":"Vùng biển nơi Vương Lâm quan sát bình minh trong mưa và lĩnh ngộ lực lượng tàn dạ.","detail":"Biển trên Thủy Linh tinh là không gian trực tiếp của cảnh mặt trời mọc trong mưa ở chương này. Hình tượng mặt trời từ mặt biển phá tan màn đêm trở thành nguồn cảm ngộ để Vương Lâm nắm bắt Tàn Dạ.","theLucLienQuan":[],"nguon":["@c0929"]},{"id":"dinh-nui-cao","name":"Đỉnh núi cao","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Vương Lâm khoanh chân bất động và thi triển Tàn Dạ.","detail":"Trận đối đầu giữa Vương Lâm và Phù Phong tử diễn ra tại đỉnh núi cao này. Vương Lâm vẫn ngồi khoanh chân, chỉ nâng tay thi triển Tàn Dạ để phá thế công của Phù Phong tử.","theLucLienQuan":[],"nguon":["@c0930"]},{"id":"cung-dien-cua-vuong-lam-tren-thuy-linh-tinh","name":"Cung điện của Vương Lâm trên Thủy Linh tinh","cn":"","capDo":"khac","parentId":"thuy-linh-tinh","blurb":"Nơi Vương Lâm bày cấm chế và luyện hóa Ngân Y Luyện Thi trong hơn nửa tháng.","detail":"Vương Lâm phong kín cung điện bằng nhiều tầng cấm chế, dùng Tâm Cấm thuật và la bàn truyền nhân Phá Diệt Cấm làm trung tâm để trấn áp, phá xiềng rồi luyện hóa nữ thi.","theLucLienQuan":[],"nguon":["@c0931"]},{"id":"tinh-khong-ngoai-thuy-linh-tinh","name":"Tinh không ngoài Thủy Linh tinh","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Không gian bên ngoài Thủy Linh tinh, nơi Tư Đồ Nam đứng ngoài tinh cầu và thi triển thần thông phá trận. Lốc xoáy của hắn hấp thu sức mạnh thiên địa trong vùng tinh không này.","detail":"Tư Đồ Nam từ ngoài Thủy Linh tinh áp sát tinh cầu, dùng thần thức quét ngang rồi thi triển các chỉ pháp phá phòng hộ. Đây là chiến trường trực tiếp giữa hắn và ba tầng hào quang màu đen quanh tinh cầu.","theLucLienQuan":["Trần Đạo Tam Tử"],"nguon":["@c0932"]},{"id":"cung-dien-cua-phu-phong-tu","name":"Cung điện của Phù Phong tử","cn":"","capDo":"khac","parentId":"thuy-linh-tinh","blurb":"Cung điện xa xa trên Thủy Linh tinh nơi Phù Phong tử ở khi thần thức Tư Đồ Nam quét tới. Từ đây, hắn bấm pháp quyết ứng đối trước khi thần thức kia thu hồi.","detail":"Trong lúc thần thức Tư Đồ Nam quét ngang tinh cầu, Phù Phong tử ở cung điện xa xa nhíu mày, hai mắt hiện ánh sáng lờ mờ và bấm pháp quyết chỉ về phía trước.","theLucLienQuan":[],"nguon":["@c0932"]},{"id":"dinh-nui-cam-ngo-tan-da","name":"Đỉnh núi cảm ngộ Tàn Dạ","cn":"","capDo":"khac","parentId":"thuy-linh-tinh","blurb":"Đỉnh núi nơi Vương Lâm từng cảm ngộ lực lượng Tàn Dạ và chương này cùng Tư Đồ Nam uống rượu ôn chuyện.","detail":"Sau cuộc luận bàn, Vương Lâm đưa Tư Đồ Nam tới đỉnh núi từng gắn với cảm ngộ Tàn Dạ. Tại đây hai người đặt bàn ngọc, uống rượu và kể lại biến cố nhiều năm xa cách.","theLucLienQuan":[],"nguon":["@c0934"]},{"id":"phuong-loan-tinh","name":"Phượng Loan tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu được Tư Đồ Nam nhắc là nơi hắn từng du hí nhân gian và nghe tin cuộc chiến La Thiên với Liên minh.","detail":"Trong cuộc trò chuyện với Vương Lâm, Tư Đồ Nam nhắc tới Phượng Loan tinh như một địa điểm trong hành trình của mình, nơi hắn nghe tin về chiến sự giữa La Thiên và Liên minh.","theLucLienQuan":["Phượng Loan tinh"],"nguon":["@c0934"]},{"id":"dong-hai-trieu-tich","name":"Đông Hải Triều tịch","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Địa điểm được Thiên Vận Tử ghi trong thiệp là nơi mười ngày sau mở cửa vào động phủ Tiên nhân.","detail":"Đông Hải Triều tịch là nơi Thiên Vận Tử ấn định trong thiệp mời để mở cửa vào động phủ Tiên nhân sau mười ngày. Tin này khiến các lão quái đủ tư cách vào vùng đất Yêu Linh chấn động.","theLucLienQuan":["Thiên Vận tông"],"nguon":["@c0935"]},{"id":"dong-phu-tien-nhan-trong-vung-dat-yeu-linh","name":"Động phủ Tiên nhân trong vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Động phủ sắp mở ở vùng đất Yêu Linh, bị nghi có Tiên nhân sống sót hoặc Tiên Đế Thanh Lâm tồn tại bên trong.","detail":"Động phủ Tiên nhân trong vùng đất Yêu Linh là mục tiêu được Thiên Vận Tử dùng thiệp mời để triệu tập các lão quái. Nơi này hấp dẫn họ không chỉ vì pháp bảo và tiên thuật, mà còn vì khả năng có Thanh Lâm và bí mật bước tu đạo thứ ba.","theLucLienQuan":["Thiên Vận tông","Yêu Linh"],"nguon":["@c0935"]},{"id":"la-thien-tinh-vuc","name":"La Thiên Tinh vực","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Tinh vực nơi danh tiếng của Vương Lâm được Tư Đồ Nam nhắc là đã lẫy lừng.","detail":"La Thiên Tinh vực được Tư Đồ Nam nhắc tới khi nói danh tiếng của Vương Lâm ở nơi này đã rất lớn, cho thấy vị thế hiện tại của Vương Lâm không còn như năm xưa.","theLucLienQuan":["La Thiên"],"nguon":["@c0935","@c0940"]},{"id":"nuoc-trieu","name":"Nước Triệu","cn":"","capDo":"quoc-gia","parentId":null,"blurb":"Quê cũ trong hồi ức, nơi Vương Lâm năm xưa nếu không có Tư Đồ Nam thì đã chết.","detail":"Nước Triệu được nhắc trong hồi ức ân nghĩa giữa Vương Lâm và Tư Đồ Nam. Vương Lâm cho rằng nếu không có Tư Đồ Nam ở thời điểm năm xưa tại nước Triệu, hắn đã không thể sống đến hiện tại.","theLucLienQuan":[],"nguon":["@c0935"]},{"id":"ti-thien-quan","name":"Tị Thiên quan","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi gắn với Lý Mộ Uyển trong ký ức và nỗi đau tình cảm của Vương Lâm.","detail":"Tị Thiên quan được nhắc khi Vương Lâm nghĩ tới Lý Mộ Uyển trong cuộc trò chuyện với Tư Đồ Nam về đạo lữ, mất mát và nỗi bất lực trước sinh tử.","theLucLienQuan":[],"nguon":["@c0935"]},{"id":"trieu-tich","name":"Triều tịch","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Lốc xoáy khổng lồ không truyền lực hút, là cửa lớn vào vùng đất Yêu Linh. Nơi này trở thành điểm tụ tập của Thiên Vận tử, Lăng Thiên Hậu và nhiều lão quái.","detail":"Triều tịch là cửa vào vùng đất Yêu Linh trong sự kiện tiến vào động phủ nghi là nơi Thanh Lâm bế quan. Đến ngày thứ mười, nhiều tu sĩ và đại thần thông giả tụ tập quanh lốc xoáy này để chờ mở đường tiến vào.","theLucLienQuan":["Thiên Vận tông","Đại La Kiếm Tông","Bộ lạc Luyện Hồn"],"nguon":["@c0936"]},{"id":"dong-phu-sau-trong-vung-dat-yeu-linh","name":"Động phủ sâu trong vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Động phủ được cho là nơi Thanh Lâm bế quan sau khi bị thương nặng vì đại họa Tiên Giới. Tin rằng người bên trong chưa khôi phục khiến nơi này trở thành mục tiêu của các đại thần thông giả.","detail":"Các dấu hiệu gần đây khiến giới tu sĩ tin động phủ sâu trong vùng đất Yêu Linh là nơi Thanh Lâm bế quan năm xưa. Việc xâm nhập nơi này bị xem là cơ hội lớn vì Thanh Lâm từng là Tiên Đế chí tôn đã bước vào bước tu đạo thứ ba.","theLucLienQuan":["Yêu Linh"],"nguon":["@c0936"]},{"id":"tien-phu-cua-thanh-lam","name":"Tiên phủ của Thanh Lâm","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Tiên phủ liên quan tới Thanh Lâm, nơi nhiều tu sĩ tin rằng người bên trong chưa khôi phục. Các lần thăm dò gần đây làm dấy lên dã tâm tiến vào của giới đại thần thông.","detail":"Tiên phủ của Thanh Lâm được nhiều lần thăm dò trong những năm gần đây. Kết quả thăm dò khiến các tu sĩ tin người trong phủ chưa khôi phục hoàn toàn, làm chuyến đi Yêu Linh trở thành cơ hội tranh đoạt nguy hiểm.","theLucLienQuan":["Yêu Linh"],"nguon":["@c0936"]},{"id":"quan-thien-yeu","name":"Quận Thiên Yêu","cn":"","capDo":"vuc","parentId":"vung-dat-yeu-linh","blurb":"Một trong các quận tại vùng đất Yêu Linh, nơi bộ lạc Luyện Hồn từng trỗi dậy. Bộ lạc này từng chiếm cứ quận Hỏa Yêu nhưng sau thiệt hại nghiêm trọng phải buông tha.","detail":"Quận Thiên Yêu là một trong hai địa bàn gắn với sự bành trướng của bộ lạc Luyện Hồn. Từ đây, lực lượng Luyện Hồn phát triển và chuẩn bị quay lại tranh đoạt quận Hỏa Yêu.","theLucLienQuan":["Bộ lạc Luyện Hồn"],"nguon":["@c0936"]},{"id":"chin-quan-yeu-linh","name":"Chín quận Yêu Linh","cn":"","capDo":"vuc","parentId":"vung-dat-yeu-linh","blurb":"Toàn bộ vùng đất Yêu Linh được chia thành chín quận. Các chi nhánh Luyện Hồn gần như lan khắp nơi để tra xét chiến trường, chiến tranh và các bộ lạc khác nhằm thu hồn phách.","detail":"Chín quận Yêu Linh là phạm vi hoạt động rộng lớn của các chi nhánh bộ lạc Luyện Hồn trong vài trăm năm. Việc chi nhánh trải khắp chín quận giúp họ liên tục hấp thu hồn phách và tích lũy lực lượng.","theLucLienQuan":["Bộ lạc Luyện Hồn","Yêu Linh"],"nguon":["@c0936"]},{"id":"tinh-khong-ngoai-thien-van-tinh","name":"Tinh không ngoài Thiên Vận tinh","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Tinh không ngoài Thiên Vận tinh là nơi đoàn Lôi Cát chở Vương Lâm xuất hiện từ xa trước Đông Hải Triều tịch. Sự xuất hiện ấy khiến đám tu sĩ đang chờ mở Triều tịch chấn động.","detail":"Khu vực tinh không này nằm ngoài Thiên Vận tinh, gần nơi các đại thần thông và đông đảo tu sĩ tụ tập chờ Đông Hải Triều tịch mở. Từ đây, thân hình Cự Ma Tộc khổng lồ của Lôi Cát bay tới, lần lượt để lộ các trợ lực của Vương Lâm.","theLucLienQuan":["Thiên Vận tinh","Cự Ma Tộc"],"nguon":["@c0937"]},{"id":"dong-phu-thu-nam","name":"Động phủ thứ năm","cn":"","capDo":"khac","parentId":"dong-hai-trieu-tich","blurb":"Động phủ thứ năm là mục tiêu Thiên Vận tử tuyên bố sẽ mở sau khi bốn Tiên phủ đã toàn bộ mở ra. Lối vào được tạo thông qua hố đen nghịch chuyển trong Đông Hải Triều tịch.","detail":"Sau khi dùng lệnh bài bảy màu mở Đông Hải Triều tịch, Thiên Vận tử nói bốn Tiên phủ đã toàn bộ mở và lần này sẽ mở động phủ thứ năm. Hố đen xuất hiện từ lốc xoáy nghịch chuyển tỏa ra khí tức Yêu Linh quen thuộc với Vương Lâm, cho thấy động phủ này nằm sau tuyến Triều tịch.","theLucLienQuan":["Thiên Vận tử","Yêu Linh"],"nguon":["@c0937"]},{"id":"ho-den-loc-xoay-vao-vung-dat-yeu-linh","name":"Hố đen / lốc xoáy vào vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":"dong-hai-trieu-tich","blurb":"Cửa vào dẫn tới vùng đất Yêu Linh tại khu vực Đông Hải Triều Tịch, nơi nhiều tu sĩ theo nhau tiến nhập trong chương này.","detail":"Hố đen/lốc xoáy là thông đạo mà Thiên Vận Tử đã đi vào trước đó, sau đó Hư Không Tử, Lăng Thiên Hậu, Tôn Thiện, Vương Lâm, Tư Đồ Nam và nhiều nhóm tu sĩ lần lượt tiến nhập để tới vùng đất Yêu Linh. Sau khi một bộ phận tu sĩ xung quanh chen vào, hố đen đột ngột ngừng xoay, xoay ngược rồi biến mất, khiến vài người mắc kẹt bị sụp đổ thân thể.","theLucLienQuan":["Liên minh","Côn Hư"],"nguon":["@c0938"]},{"id":"do-thanh-hoa-yeu","name":"Đô thành Hỏa Yêu","cn":"","capDo":"thanh","parentId":"quan-hoa-yeu","blurb":"Thành trì cuối cùng của Hỏa Yêu Linh quân trong quận Hỏa Yêu, bị bộ lạc Luyện Hồn vây hãm và buộc đầu hàng.","detail":"Đô thành Hỏa Yêu là nơi Hỏa Yêu Linh quân cố thủ sau khi các thế lực nhỏ trong quận Hỏa Yêu hoặc đầu hàng hoặc bị tiêu diệt. Đại quân bộ lạc Luyện Hồn bao vây thành, Âu Dương Hoa ép hai Yêu Soái Mộc Vận và Hạt Kim quy hàng; sau khi Hạt Kim bị Thập Tam giết và lệnh Hồn diệt được phát ra, người con gái mặc áo giáp xanh trên tường thành chấp nhận đầu hàng. Từ đó nơi này hoàn toàn trở thành đô thành của bộ lạc Luyện Hồn.","theLucLienQuan":["Bộ lạc Luyện Hồn","Hỏa Yêu Linh quân","Quận Hỏa Yêu"],"nguon":["@c0938"]},{"id":"noi-linh-hon-co-yeu-ngay-truoc","name":"Nơi Linh hồn Cổ Yêu ngày trước","cn":"","capDo":"khac","parentId":"do-thanh-hoa-yeu","blurb":"Vị trí trong đô thành Hỏa Yêu từng gắn với Linh hồn Cổ Yêu, sau chiến thắng được chọn làm nơi đặt tượng đá Lão tổ.","detail":"Sau khi đô thành Hỏa Yêu đầu hàng, bộ lạc Luyện Hồn chuẩn bị đưa tượng đá màu đen của Lão tổ vào thành và đặt tại nơi Linh hồn Cổ Yêu ngày trước. Việc thay thế vị trí này cho thấy bộ lạc Luyện Hồn không chỉ chiếm giữ thành trì mà còn đổi trung tâm tinh thần của quận Hỏa Yêu sang tín ngưỡng Lão tổ.","theLucLienQuan":["Bộ lạc Luyện Hồn","Quận Hỏa Yêu"],"nguon":["@c0938"]},{"id":"moc-yeu-quan","name":"Mộc Yêu Quận","cn":"","capDo":"vuc","parentId":"yeu-linh-chi-dia","blurb":"Một quận trong Yêu Linh chi địa, nơi dị tượng lốc xoáy trên trời kéo theo sự thức động của một tồn tại yêu dị dưới hồ.","detail":"Mộc Yêu Quận được nhắc tới qua một hạp cốc hẻo lánh có hồ nước dưới đáy. Khi bầu trời Yêu Linh chi địa đầy lốc xoáy, mặt hồ tại đây nổi sóng và trồi lên một khuôn mặt yêu dị không giống người, kẻ nói rằng đã chờ ngày này rất lâu.","theLucLienQuan":[],"nguon":["@c0939"]},{"id":"hap-coc-moc-yeu-quan","name":"Hạp cốc Mộc Yêu Quận","cn":"","capDo":"khac","parentId":"moc-yeu-quan","blurb":"Hạp cốc sâu, ẩm ướt trong Mộc Yêu Quận, có hồ nước dưới đáy và là nơi khuôn mặt yêu dị xuất hiện.","detail":"Địa điểm hẻo lánh trong Mộc Yêu Quận, bên dưới có hồ nước tĩnh lặng. Khi dị tượng lốc xoáy bao phủ bầu trời Yêu Linh chi địa, hồ nước nổi sóng, từ đó trồi lên một khuôn mặt yêu dị nhìn trời và xác nhận thời điểm chờ đợi đã tới.","theLucLienQuan":[],"nguon":["@c0939"]},{"id":"binh-nguyen-co-xanh-thao-nguyen-cam-che","name":"Bình nguyên cỏ xanh / thảo nguyên cấm chế","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Vùng thảo nguyên xanh trong Yêu Linh chi địa, bề ngoài bình thường nhưng thực chất che giấu một khu cấm chế khổng lồ và Tiên giới chi trận.","detail":"Bình nguyên có mùi cỏ kỳ dị, từng khiến một chi nhánh Luyện Hồn bộ lạc từ bỏ vì Hồn phiên mất uy lực. Bên dưới nơi này là khu cấm chế lớn, nếu mở ra có uy lực hủy diệt mạnh, đồng thời che giấu truyền tống trận cổ từ thời Tiên giới chưa sụp đổ.","theLucLienQuan":["Luyện Hồn bộ lạc"],"nguon":["@c0939"]},{"id":"nam-toa-tien-phu-yeu-linh-chi-dia","name":"Năm tòa Tiên phủ của Yêu Linh chi địa","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Hệ thống năm tòa Tiên phủ trong Yêu Linh chi địa, liên hệ với truyền tống trận cổ và cơ chế mở phủ nhiều tầng.","detail":"Các Tiên phủ trong Yêu Linh chi địa có thể được tiến vào nhờ phương thức đặc thù và tín vật thông qua Tiên giới chi trận. Cơ chế được hé lộ là bốn tòa Tiên phủ bên ngoài cần được mở hết thì tòa Tiên phủ thứ năm mới có thể mở ra.","theLucLienQuan":[],"nguon":["@c0939"]},{"id":"tien-phu-hinh-chu-quy","name":"Tiên phủ hình chữ Quy","cn":"","capDo":"khac","parentId":"nam-toa-tien-phu-yeu-linh-chi-dia","blurb":"Một Tiên phủ trong Yêu Linh chi địa, nơi Vương Nguy và Hồ Quyên cư trú lâu năm và chờ thời điểm kế hoạch khởi động.","detail":"Tiên phủ có bố cục hình chữ Quy, gồm nhiều lầu các vây quanh một đại điện cao nhất. Nơi này có tiên khí nhưng cũng mang vẻ lạnh lẽo nếu thiếu Vương Nguy và Hồ Quyên; hai người ở đây nhận biết dị tượng và bàn về kế hoạch đã chuẩn bị nhiều năm.","theLucLienQuan":["Vân Tiên đạo lữ"],"nguon":["@c0939"]},{"id":"tien-phu-thu-tu-cua-vuong-lam","name":"Tiên phủ thứ tư của Vương Lâm","cn":"","capDo":"khac","parentId":"nam-toa-tien-phu-yeu-linh-chi-dia","blurb":"Tòa Tiên phủ mà Vương Lâm nắm thạch bàn và lệnh bài, còn nhiều cấm chế cần phá để tiến vào vị trí trung tâm.","detail":"Tiên phủ thứ tư là tuyến Vương Lâm giao cho Tư Đồ Nam và nhóm cao thủ xử lý sau khi trở lại Yêu Linh chi địa. Vương Lâm đưa thạch bàn, điều chỉnh lệnh bài và chỉ lại những chỗ cấm chế từng phá giải để nhóm Tư Đồ Nam thuận lợi vào phủ, tiếp tục phá cấm hướng tới trung tâm.","theLucLienQuan":[],"nguon":["@c0939"]},{"id":"phong-yeu-quan","name":"Phong Yêu Quận","cn":"","capDo":"vuc","parentId":"yeu-linh-chi-dia","blurb":"Một quận trong Yêu Linh chi địa, nơi Diêu Tích Tuyết tiếp nhận truyền thừa Phong Yêu để đổi lấy lực lượng báo thù.","detail":"Phong Yêu Quận có Hoàng cung và hệ thống hầm ngầm thấm đầy thi khí. Khi Vương Lâm trở lại Yêu Linh chi địa, hắn thoáng cảm nhận từ phương hướng Phong Yêu Quận một luồng oán khí ngập trời khiến tâm thần lay động.","theLucLienQuan":["Phong Yêu"],"nguon":["@c0939"]},{"id":"hoang-cung-phong-yeu-quan-ham-ngam-duoi-hoang-thanh","name":"Hoàng cung Phong Yêu Quận / hầm ngầm dưới Hoàng thành","cn":"","capDo":"khac","parentId":"phong-yeu-quan","blurb":"Khu thánh địa dưới lòng đất của Phong Yêu Quận, nơi Diêu Tích Tuyết chịu thi khí và truyền thừa Phong Yêu.","detail":"Bên dưới Hoàng cung Phong Yêu Quận là không gian ngầm có hang động đá vôi khổng lồ và nhiều động nhỏ như tổ ong, tụ thi khí vào hang trung tâm. Diêu Tích Tuyết ngồi tại đây, thân thể và dung nhan bị thi khí tàn phá trong quá trình tiếp nhận lực lượng Phong Yêu.","theLucLienQuan":["Phong Yêu"],"nguon":["@c0939"]},{"id":"co-yeu-thanh","name":"Cổ Yêu thành","cn":"","capDo":"thanh","parentId":"yeu-linh-chi-dia","blurb":"Thành trì được nhắc trong hồi tưởng, nơi Vương Lâm từng xông vào để cứu Thập Tam và Hổ Bào.","detail":"Cổ Yêu thành xuất hiện trong ký ức của Vương Lâm về quá khứ tại Yêu Linh chi địa. Hắn từng xông vào nơi này, đối diện hơn mười vạn đại quân yêu tướng để cứu Thập Tam và Hổ Bào, trước khi chuyện Hổ Bào phản bội trở thành vết nhớ sâu sắc.","theLucLienQuan":[],"nguon":["@c0939"]},{"id":"thung-lung-phia-sau-hoang-cung-do-thanh","name":"Thung lũng phía sau hoàng cung của Đô thành","cn":"","capDo":"khac","parentId":"do-thanh-hoa-yeu","blurb":"Thung lũng phía sau hoàng cung của Đô thành là nơi đặt tượng đá màu đen mang hình Vương Lâm. Đây cũng là địa điểm năm xưa Vương Lâm phóng xuất Cổ Yêu Bối La để nuốt Hỏa Yêu Linh.","detail":"Sau khi hoàn thành tâm nguyện với Luyện Hồn Tông, Vương Lâm một mình tới thung lũng này để kiểm tra tượng đá màu đen. Quá khứ nơi đây gắn với sự kiện Cổ Yêu Bối La nuốt Hỏa Yêu Linh.","theLucLienQuan":["Luyện Hồn Tông","Yêu Linh"],"nguon":["@c0940"]},{"id":"thung-lung-trong-hoa-yeu-quan","name":"Thung lũng trong Hỏa Yêu Quận","cn":"","capDo":"khac","parentId":"hoa-yeu-quan-map","blurb":"Thung lũng ở Hỏa Yêu Quận, nơi Vương Lâm đặt và thăm dò bức tượng đá màu đen của Luyện Hồn bộ lạc.","detail":"Tại thung lũng này, khi Vương Lâm đối diện tượng đá màu đen, dị biến nguyên thần bùng phát; lôi đình trên hơn phân nửa Yêu Linh chi địa bị Thái Cổ Lôi Long dẫn động hội tụ về đây rồi nhập vào cơ thể hắn để trấn áp lực lượng quỷ dị từ tượng đá.","theLucLienQuan":["Luyện Hồn bộ lạc","Luyện Hồn Tông","Hỏa Yêu Quận"],"nguon":["@c0941"]},{"id":"cuc-thanh-thien-yeu-quan-hong-thanh","name":"Cực Thành của Thiên Yêu Quận / Hồng Thành năm đó","cn":"","capDo":"thanh","parentId":"quan-thien-yeu","blurb":"Thành cũ của Thiên Yêu Quận bên dòng sông, nơi Vương Lâm từng đến nhiều trăm năm trước và trở lại trong chương này.","detail":"Sau nhiều năm chiến tranh giữa Thiên Yêu Quận và Hỏa Yêu Quận, Cực Thành không còn phồn hoa như trước. Vương Lâm trở lại nơi này, mua rượu ở tửu phô cũ, ngồi bên sông hồi tưởng thuyền hoa, tiếng đàn và cố nhân, rồi gặp lại Đế Quân.","theLucLienQuan":["Thiên Yêu Quận"],"nguon":["@c0941"]},{"id":"dong-song-trong-cuc-thanh-thien-yeu-quan","name":"Dòng sông trong Cực Thành","cn":"","capDo":"khac","parentId":"cuc-thanh-thien-yeu-quan-hong-thanh","blurb":"Dòng sông trong Cực Thành Thiên Yêu Quận, gắn với hồi ức thuyền hoa và tiếng đàn của Vương Lâm.","detail":"Vương Lâm ngồi bên dòng sông này, cảm nhận cảnh vật đã đổi khác sau mấy trăm năm. Cuối chương, Đế Quân xuất hiện cùng rượu cũ, tiếng đàn vang lên và một chiếc thuyền lớn hiện trên sông, tái hiện một phần cảnh cũ trong ký ức của hắn.","theLucLienQuan":["Thiên Yêu Quận"],"nguon":["@c0941"]},{"id":"yeu-thap","name":"Yêu Tháp","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Địa điểm được nhắc trong ký ức của tia Yêu Thức Vân Yêu sau biến cố Vân Yêu Quận.","detail":"Trong ký ức mà Vương Lâm sưu tra từ Cổ Yêu trong tượng đá, Yêu Tháp là nơi tia Yêu Thức Vân Yêu không thể tiếp tục lưu lại sau khi Vân Yêu Quận tan tành, trước khi nó trôi dạt và nhập vào tượng đá của Luyện Hồn bộ lạc.","theLucLienQuan":["Vân Yêu Quận"],"nguon":["@c0941"]},{"id":"tien-phu-thu-nam","name":"Tiên phủ thứ năm","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Tiên phủ được Bối La nhắm tới trong giao dịch với Vương Lâm.","detail":"Bối La yêu cầu Vương Lâm giữ lại một danh ngạch tiến nhập Tiên phủ thứ năm. Đổi lại, hắn hứa giao bốn Quận trong chín Quận Yêu Linh chi địa cho Luyện Hồn bộ lạc.","theLucLienQuan":["Cổ Yêu Bối La","Luyện Hồn Tông"],"nguon":["@c0942"]},{"id":"bon-quan-trong-chin-quan-yeu-linh-chi-dia","name":"Bốn Quận trong chín Quận của Yêu Linh chi địa","cn":"","capDo":"vuc","parentId":"yeu-linh-chi-dia","blurb":"Phần lãnh địa Bối La hứa giao cho Luyện Hồn bộ lạc làm lễ vật.","detail":"Bốn Quận này được nêu trong điều kiện trao đổi của Bối La: nếu Vương Lâm giữ một danh ngạch vào Tiên phủ thứ năm, chúng sẽ được dâng cho Luyện Hồn bộ lạc.","theLucLienQuan":["Cổ Yêu Bối La","Luyện Hồn Tông","Yêu Linh"],"nguon":["@c0942"]},{"id":"de-do-yeu-linh","name":"Đế đô","cn":"","capDo":"thanh","parentId":"yeu-linh-chi-dia","blurb":"Nơi Đế Kiếm được triệu tới trước khi giao cho Vương Lâm.","detail":"Đế Quân triệu Đế Kiếm từ đế đô bằng một đạo kiếm khí xé gió bay tới chỗ ông và Vương Lâm.","theLucLienQuan":["Yêu Linh","Đế Quân"],"nguon":["@c0942"]},{"id":"bo-song-ha-dao-yeu-linh","name":"Bờ sông / hà đạo","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Nơi Vương Lâm và Đế Quân uống rượu qua đêm.","detail":"Bờ sông trong Yêu Linh chi địa là nơi Vương Lâm và Đế Quân uống rượu, nghe tiếng đàn từ chiếc thuyền ngoài sông và nói chuyện về điều kiện của Bối La cùng ủy thác Đế Kiếm chi linh.","theLucLienQuan":["Yêu Linh"],"nguon":["@c0942"]},{"id":"dong-phu-tien-nhan-hinh-chu-hoi","name":"Động phủ tiên nhân hình chữ Hồi","cn":"","capDo":"khac","parentId":"tien-phu-thu-tu-cua-vuong-lam","blurb":"Cấu trúc tổng thể của Tiên phủ thứ tư theo nhận định của Phù Phong Tử.","detail":"Phù Phong Tử cho rằng Tiên phủ thứ tư có hình chữ Hồi, vị trí nhóm đang đứng là nơi giao giới trong ngoài, qua sông là Nội phủ.","theLucLienQuan":[],"nguon":["@c0942"]},{"id":"con-song-nho-trong-tien-phu","name":"Con sông nhỏ trong Tiên phủ","cn":"","capDo":"khac","parentId":"tien-phu-thu-tu-cua-vuong-lam","blurb":"Con sông tràn ngập tiên khí và sương mù ngăn giữa ngoại vi với Nội phủ.","detail":"Con sông nhỏ nằm trước Nội phủ, có tiên khí và sương mù bao phủ, bị cấm chế phong tỏa. Đại Đầu đề xuất không qua cầu đá mà phá cấm bên cạnh con sông để tiến vào.","theLucLienQuan":[],"nguon":["@c0942"]},{"id":"cau-da-trong-tien-phu","name":"Cầu đá trong Tiên phủ","cn":"","capDo":"khac","parentId":"tien-phu-thu-tu-cua-vuong-lam","blurb":"Đường duy nhất bắc qua con sông nhỏ để vào Nội phủ.","detail":"Cầu đá bị cấm chế phức tạp chặn lại, khiến nhóm Tư Đồ Nam bị cản năm canh giờ. Phù Phong Tử lo cưỡng ép phá cấm có thể sinh biến cố, còn Vương Lâm nhận ra nơi này có sát khí.","theLucLienQuan":[],"nguon":["@c0942"]},{"id":"noi-phu-tien-phu-thu-tu","name":"Nội phủ","cn":"","capDo":"khac","parentId":"tien-phu-thu-tu-cua-vuong-lam","blurb":"Khu vực bên trong Tiên phủ thứ tư nằm sau con sông và cầu đá.","detail":"Nội phủ là mục tiêu tiến vào của nhóm phá cấm. Muốn tới đó, nhóm phải vượt qua con sông nhỏ và cấm chế cầu đá ở ranh giới trong ngoài.","theLucLienQuan":[],"nguon":["@c0942"]},{"id":"pham-vi-tram-buoc-truoc-cau-da","name":"Phạm vi trăm bước trước cầu đá","cn":"","capDo":"khac","parentId":"tien-phu-thu-tu-cua-vuong-lam","blurb":"Khu vực cấm chế chủ chốt nằm trước cầu đá trong Tiên phủ.","detail":"Bề ngoài khu vực này bình tĩnh nhưng ẩn sát khí, có hàng vạn cấm chế liên kết thành chỉnh thể. Do gần con sông, biến hóa cấm chế cuối cùng quy về hai hình thái bùn đất và thủy khí, đồng thời có dấu hiệu bị người hoặc vật bên trong Tiên phủ thao khống.","theLucLienQuan":[],"nguon":["@c0943"]},{"id":"dai-dien-trong-tien-phu","name":"Đại điện trong Tiên phủ","cn":"","capDo":"khac","parentId":"tien-phu-thu-tu-cua-vuong-lam","blurb":"Cung điện lớn nằm sâu bên trong Tiên phủ, nơi truyền ra uy nghiêm đáng sợ.","detail":"Sau khi vượt qua cầu đá, nhóm Vương Lâm nhìn thấy không gian trong Tiên phủ như hoa viên, có lầu các dày đặc và đại điện điêu long khắc phượng. Bên ngoài đại điện có Tiên thú lạ trang trí cùng mười kim tượng mặc giáp làm từ huyền kim, còn bên trong truyền ra uy nghiêm bao phủ bốn phía.","theLucLienQuan":[],"nguon":["@c0943"]},{"id":"co-than-chi-dia","name":"Cổ Thần chi địa","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Vương Lâm năm xưa tự học cấm chế thuật.","detail":"Cổ Thần chi địa được nhắc như điểm khởi đầu của cấm chế thuật Vương Lâm. Từ nền tảng tự học ở nơi này, qua hơn ngàn năm hoàn thiện và kế thừa Phá Diệt Cấm tại La Thiên, năng lực cấm chế của hắn đạt đại thành.","theLucLienQuan":["Cổ Thần"],"nguon":["@c0943"]},{"id":"dai-dien-trung-tam-tien-phu","name":"Đại điện trung tâm Tiên phủ","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Đại điện nằm sâu bên trong hoa viên Tiên phủ. Khi Hoa Linh tan rã, từ đây vang lên tiếng kêu bén nhọn và mười Tôn Tiên binh xuất động.","detail":"Đại điện trung tâm là điểm sâu hơn mà Phù Phong Tử nhìn tới trong Tiên phủ. Sự xuất hiện của mười Tiên binh từ khu vực này cho thấy nơi đây có cơ chế thủ hộ mạnh hơn hoa viên bên ngoài.","theLucLienQuan":["Tiên phủ"],"nguon":["@c0944"]},{"id":"hoa-vien-tien-phu","name":"Hoa viên Tiên phủ","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Hoa viên rộng trong Tiên phủ, phủ đầy hoa cỏ tỏa Vũ hậu độc hương. Bên dưới hoa là hài cốt nữ đồng, khiến nơi này thực chất giống một nghĩa địa sinh ra Hoa Linh.","detail":"Khi Vương Lâm vượt cầu đá, hoa viên phía trước chuyển động và phóng ra mùi hương độc. Ngân thi hút độc khiến Hoa Linh hiện hình, sau đó sương trắng của nàng làm hoa cỏ héo rũ và kích hoạt Tiên binh từ đại điện.","theLucLienQuan":["Tiên phủ","Vũ chi Tiên giới"],"nguon":["@c0944"]},{"id":"man-suong-trang","name":"Màn sương trắng","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Khu vực sương trắng trong Tiên phủ, nơi Tiên binh định xông vào trước khi bị nhóm lão quái ngăn lại. Sau khi Tiên binh bị xử lý, màn sương nhanh chóng co rút.","detail":"Màn sương trắng nằm trong chiến trường Tiên phủ quanh tuyến tiến về đại điện. Nhất Tinh Tử lao về phía nơi này, Phù Phong Tử giữ Tiên binh cuối cùng không để nó xông vào, rồi màn sương thu lại sau khi Tiên binh bị giải quyết.","theLucLienQuan":["Tiên phủ"],"nguon":["@c0945"]},{"id":"lau-cac-quanh-dai-dien","name":"Lầu các quanh đại điện","cn":"","capDo":"khac","parentId":"dai-dien-trong-tien-phu","blurb":"Những lầu các quanh đại điện Tiên phủ có thể biến ảo phương vị. Ánh sáng từ chúng hợp lại thành quy xác phòng hộ bao phủ đại điện.","detail":"Khi Vương Lâm tiến tới đại điện, các lầu các xung quanh biến thành hư ảnh, di động vị trí và phát cường quang. Cường quang dung hợp thành hình mai rùa, tạo nên lớp phòng hộ bảo vệ đại điện.","theLucLienQuan":["Tiên phủ"],"nguon":["@c0945"]},{"id":"yeu-linh-tien-phu","name":"Yêu Linh Tiên phủ","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Mục tiêu phía sau động phủ mà Vương Lâm nhất định muốn tiến vào.","detail":"Yêu Linh Tiên phủ được Vương Lâm coi là nơi nhất định phải vào. Trong tình thế đối đầu nữ tử áo trắng, hắn còn nghĩ tới phương án tìm Cổ Yêu Bối La phá nát nơi này nếu không thể vượt qua bằng cách đánh cược.","theLucLienQuan":["Yêu Linh","Cổ Yêu"],"nguon":["@c0947"]},{"id":"dai-dien-hac-am","name":"Đại điện hắc ám","cn":"","capDo":"khac","parentId":"dong-phu-tren-tinh-cau-bo-hoang","blurb":"Đại điện hắc ám là nội điện nơi Hoa Phi Hàm Yên dẫn Vương Lâm bước vào. Bên trong có chín pho tượng, trong đó pho tượng trung tâm tỏa uy áp khiến Vương Lâm thổ huyết và bộc phát Cổ Thần lực.","detail":"Đại điện hắc ám nằm sâu trong động phủ, bóng tối ở đây hạn chế cả tầm nhìn lẫn thần thức. Sau khi Hoa Phi Hàm Yên tạo tinh quang, Vương Lâm nhìn thấy đại điện giống đạo quán với chín pho tượng, đặc biệt pho tượng trung tâm mặc hoàng bào thêu chín tử long và phát ra uy áp cực mạnh.","theLucLienQuan":[],"nguon":["@c0948"]},{"id":"hoa-hai","name":"Hoa hải","cn":"","capDo":"khac","parentId":"dong-phu-tren-tinh-cau-bo-hoang","blurb":"Hoa hải là vùng biển hoa hình thành trên mặt đất quanh nơi Vương Lâm, Tư Đồ Nam và Hoa Phi Hàm Yên đối đầu. Khung cảnh này xuất hiện trước khi diễn biến chuyển vào đại điện hắc ám.","detail":"Trong động phủ, cánh hoa rơi phủ kín mặt đất thành biển hoa, tạo nên không gian tĩnh lặng và kỳ dị quanh cuộc giằng co. Hoa hải là bối cảnh nơi Hoa Phi Hàm Yên dao động trước thi thể Thanh Sương và nơi Tư Đồ Nam xuất hiện cứu viện.","theLucLienQuan":[],"nguon":["@c0948"]},{"id":"dai-dien-trong-dong-phu-thu-tu","name":"Đại điện trong động phủ thứ tư","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Đại điện nơi đặt pho tượng Tiên Đế Thanh Lâm và nơi Hoa Phi Hàm Yên khảo nghiệm Vương Lâm.","detail":"Trong đại điện có pho tượng Tiên Đế Thanh Lâm phát ra uy áp hùng mạnh, Hoa Phi Hàm Yên xuất hiện và mở truyền tống trận. Sau khi Vương Lâm kích hoạt đại trận khối đá màu đen, khu vực đại điện vẫn là ngoại lệ không nằm trong phần hắn khống chế.","theLucLienQuan":["Tiên đế bát phi","Tiên phủ Thanh Lâm"],"nguon":["@c0949"]},{"id":"tien-phu-chan-chinh","name":"Tiên phủ chân chính","cn":"","aliases":["chỗ bế quan của Thanh Lâm"],"capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Mục tiêu sau phong ấn, nơi gắn với chỗ bế quan chữa thương của Tiên Đế Thanh Lâm.","detail":"Hoa Phi nói chỉ khi bốn cửa vào đồng thời mở ra thì vùng đất Yêu Linh mới xuất hiện thông đạo chân chính tới nơi bế quan của Thanh Lâm, tức tiên phủ chân chính phía sau phong ấn.","theLucLienQuan":["Tiên phủ Thanh Lâm"],"nguon":["@c0949"]},{"id":"khong-gian-hu-ao-sau-truyen-tong-tran","name":"Không gian hư ảo sau truyền tống trận","cn":"","capDo":"khac","parentId":"dai-dien-trong-dong-phu-thu-tu","blurb":"Không gian có đại trận khổng lồ và khối đá màu đen sau truyền tống trận Hoa Phi mở.","detail":"Vương Lâm đi qua truyền tống trận vào không gian hư ảo này, dùng chìa khóa tiên phủ kích hoạt khối đá màu đen để đại trận vận chuyển và sinh quyền khống chế động phủ thứ tư.","theLucLienQuan":["Tiên phủ Thanh Lâm"],"nguon":["@c0949"]},{"id":"cho-sau-trong-dai-dien","name":"Chỗ sâu trong đại điện","cn":"","capDo":"khac","parentId":"dai-dien-trong-dong-phu-thu-tu","blurb":"Nơi Hoa Phi Hàm Yên rời khỏi tầm mắt Vương Lâm và hiện nguyên trạng hoa tiên.","detail":"Sau khi để Vương Lâm đi tiếp, Hoa Phi biến mất trong bạch quang tại chỗ sâu trong đại điện, để lộ sự thật Hoa Phi đã chết và chỉ còn một gốc hoa tiên nở trong bóng tối.","theLucLienQuan":["Tiên đế bát phi"],"nguon":["@c0949"]},{"id":"binh-nguyen-chinh-bac-vung-dat-yeu-linh","name":"Bình nguyên chính bắc vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Bình nguyên ở chính bắc vùng đất Yêu Linh là nơi cột sáng đầu tiên phóng lên trời. Tiên khí từ đây ban đầu tạo thế cân bằng với yêu khí trong phạm vi trăm dặm.","detail":"Tại chính bắc vùng đất Yêu Linh, mây đen tụ lại, tiếng sấm vang lên và một cột sáng từ bình nguyên phóng thẳng lên trời. Tiên khí lan ra khiến khu vực quanh cột sáng chuyển biến, nhưng ngoài trăm dặm yêu khí vẫn chiếm ưu thế.","theLucLienQuan":[],"nguon":["@c0950"]},{"id":"linh-yeu-quan-chinh-tay-vung-dat-yeu-linh","name":"Linh Yêu quận chính tây vùng đất Yêu Linh","cn":"","capDo":"vuc","parentId":"vung-dat-yeu-linh","blurb":"Linh Yêu quận ở chính tây vùng đất Yêu Linh là nơi cột sáng thứ hai bùng lên. Cột sáng này cùng các cột sáng khác mở rộng chiến trường tiên khí đối kháng yêu khí.","detail":"Sau cột sáng chính bắc, tại chính tây thuộc Linh Yêu quận lại có một cột sáng xuất hiện. Tiên khí từ cột sáng này lan ra, tham gia vào biến hóa toàn vùng đất Yêu Linh.","theLucLienQuan":[],"nguon":["@c0950"]},{"id":"chinh-nam-vung-dat-yeu-linh","name":"Chính nam vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Chính nam vùng đất Yêu Linh là phương vị xuất hiện cột sáng thứ ba. Cột sáng này khiến tiên khí cùng yêu khí triển khai thêm một chiến trường va chạm.","detail":"Cùng với chính bắc và chính tây, chính nam vùng đất Yêu Linh cũng phóng lên một cột sáng. Ba luồng tiên khí từ ba phương tạo thành nhiều chiến trường đối kháng yêu khí.","theLucLienQuan":[],"nguon":["@c0950"]},{"id":"chinh-dong-vung-dat-yeu-linh","name":"Chính đông vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Chính đông vùng đất Yêu Linh là phương vị cột sáng thứ tư xuất hiện. Cột sáng này hoàn tất thế bốn phương của đại trận phục nguyên Tiên Linh Thiên Cảnh.","detail":"Khi động phủ thứ nhất được Vương Nguy kích hoạt, cột sáng phía đông phóng lên trời. Sự xuất hiện của nó khiến bốn phương đông nam tây bắc giao thoa và hình thành đại trận cực lớn.","theLucLienQuan":[],"nguon":["@c0950"]},{"id":"dong-phu-thu-ba-vung-dat-yeu-linh","name":"Động phủ thứ ba vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Động phủ thứ ba là nơi Lăng Thiên Hậu, nam tử mặc y phục tím và Không Hư Tử ngồi trong trận pháp. Tại đây Lăng Thiên Hậu kích hoạt hắc thạch để mở trận pháp động phủ.","detail":"Trong động phủ thứ ba, Lăng Thiên Hậu gọi khói xanh và chìa khóa mơ hồ, cho dung nhập vào hắc thạch trung tâm. Hắc thạch chấn động khiến trận pháp lập tức mở ra, liên động với biến hóa cột sáng của Tiên Linh Thiên Cảnh.","theLucLienQuan":[],"nguon":["@c0950"]},{"id":"dong-phu-thu-hai-vung-dat-yeu-linh","name":"Động phủ thứ hai vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Động phủ thứ hai là nơi Thiên Vận Tử khoanh chân quan sát trận pháp mở ra. Nơi này gắn với một trong các cột sáng phục nguyên Tiên Linh Thiên Cảnh.","detail":"Thiên Vận Tử ngồi trong động phủ thứ hai, nhìn trận pháp mở ra với vẻ bình tĩnh nhưng ánh mắt lóe dị quang. Động phủ này là một mắt xích trong chuỗi động phủ mở ra đồng thời ở vùng đất Yêu Linh.","theLucLienQuan":[],"nguon":["@c0950"]},{"id":"dong-phu-thu-nhat-vung-dat-yeu-linh","name":"Động phủ thứ nhất vùng đất Yêu Linh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Động phủ thứ nhất là nơi Vương Nguy và Hồ Quyên đứng trước phong ấn để kích hoạt hắc thạch. Nơi này dẫn động cột sáng chính đông, hoàn tất đại trận bốn phương.","detail":"Trong động phủ thứ nhất, Vương Nguy và Hồ Quyên đứng trước phong ấn, dưới chân là trận pháp lớn. Vương Nguy vỗ vào hắc thạch khiến toàn bộ trận pháp vận chuyển, từ đó cột sáng chính đông bùng lên.","theLucLienQuan":["Vân Tiên Đạo Lữ"],"nguon":["@c0950"]},{"id":"thung-lung-co-thuy-dam-trong-tien-linh-thien-canh","name":"Thung lũng có thủy đàm trong Tiên Linh Thiên Cảnh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Thung lũng có thủy đàm là một trong những nơi yêu khí còn cố thủ sau khi Tiên Linh Thiên Cảnh phục nguyên. Tại đây hiện ra khuôn mặt yêu dị nhìn tiên khí quét qua bầu trời.","detail":"Dù phần lớn vùng đất đã được tiên khí phục nguyên, thung lũng này vẫn có yêu khí kiên cố như bàn thạch. Trong thủy đàm của thung lũng, một khuôn mặt yêu dị hiện lên và quan sát tiên khí trên bầu trời.","theLucLienQuan":[],"nguon":["@c0950"]},{"id":"yeu-quan-de-do","name":"Yêu quận đế đô","cn":"","capDo":"thanh","parentId":null,"blurb":"Một đế đô thuộc yêu quận trong Tiên Linh Thiên Cảnh, nơi Diêu Tích Tuyết đang khoanh chân trước khi tiên khí lan tới. Từ đây nàng hóa yêu quang rời đi.","detail":"Diêu Tích Tuyết ở bên dưới một yêu quận đế đô khi cảm nhận tiên khí trong Tiên Linh Thiên Cảnh. Yêu khí trong cơ thể nàng bùng nổ thành lốc xoáy hấp thu tiên khí, rồi nàng hóa thành yêu quang bay đi.","theLucLienQuan":["Diêu Tích Tuyết"],"nguon":["@c0951"]},{"id":"luyen-hon-tong-do-thanh","name":"Luyện Hồn Tông đô thành","cn":"","capDo":"thanh","parentId":"hoa-yeu-quan-map","blurb":"Khu vực Luyện Hồn Tông tại Hỏa Yêu Quận, bao phủ bởi màn sương đen và vô số hồn phách. Đây là nơi mấy trăm vạn đệ tử bảo vệ tượng đá Vương Lâm trước tiên phong.","detail":"Trong Hỏa Yêu Quận, Luyện Hồn Tông đô thành có màn sương đen, hồn phiên và hồn phách dày đặc. Khi tiên phong quét tới, toàn tông dùng hồn phiên tạo phòng hộ quanh tượng đá màu đen, sau đó được một phần tiên phong có ý chí trợ giúp chống các luồng tiên phong còn lại.","theLucLienQuan":["Luyện Hồn Tông"],"nguon":["@c0951"]},{"id":"trung-tam-tien-linh-thien-canh","name":"Trung tâm Tiên Linh Thiên Cảnh","cn":"","capDo":"khac","parentId":null,"blurb":"Giao điểm của bốn cột sáng trong Tiên Linh Thiên Cảnh. Tại đây dãy núi sụp đổ, chín tử long bay lên và tạo thành Cửu Long trận pháp.","detail":"Trung tâm Tiên Linh Thiên Cảnh vốn là khu vực có dãy núi ngang dọc. Khi bốn cột sáng nối lại thành vòng bảo vệ, nơi này sụp đổ, chín con tử long vạn trượng lao ra và xoay thành Cửu Long trận pháp, dẫn tới việc mở tòa động phủ thứ năm.","theLucLienQuan":[],"nguon":["@c0951"]},{"id":"trieu-tich-vuc-sau","name":"Triều Tịch vực sâu","cn":"","capDo":"khac","parentId":"hoa-yeu-quan-map","blurb":"Địa điểm có lối vào tại Hỏa Yêu Quận, từng được Vương Lâm bố trí cấm chế. Vương Nguy nhắc lại nơi này khi xác nhận cấm chế năm xưa.","detail":"Triều Tịch vực sâu được Vương Nguy nhắc tới trước Cửu Long trận pháp. Lối vào nơi này ở Hỏa Yêu Quận từng có cấm chế do Vương Lâm bố trí, dấu vết được Vương Nguy lấy ra dưới dạng một gốc cỏ.","theLucLienQuan":["Vương Lâm","Vương Nguy"],"nguon":["@c0951"]},{"id":"toa-dong-phu-thu-nam","name":"Tòa động phủ thứ năm","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Động phủ được mở khi Cửu Long trận pháp vận chuyển tại trung tâm Tiên Linh Thiên Cảnh. Tử quang từ trận pháp bao phủ mọi người, đưa họ biến mất vào trong.","detail":"Tòa động phủ thứ năm mở ra sau khi chín tử long tạo thành Cửu Long trận pháp. Khi trận pháp vận chuyển, tử quang bùng lên trong phạm vi mấy trăm trượng, thân ảnh các nhóm đại tu biến mất và động phủ chính thức mở.","theLucLienQuan":["Thiên Vận Tử","Vương Lâm","Vân Tiên Đạo Lữ","Bối La"],"nguon":["@c0951"]},{"id":"toa-dong-phu-thu-tu","name":"Tòa động phủ thứ tư","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Động phủ được Vương Nguy nhắc tới qua việc Vương Lâm từng lấy chìa khóa của nó. Chương này chỉ nhắc lại như một dấu mốc liên quan giữa Vương Lâm và Vân Tiên Đạo Lữ.","detail":"Trước Cửu Long trận pháp, Vương Nguy hỏi Vương Lâm có phải người từng lấy đi chìa khóa của tòa động phủ thứ tư hay không. Việc này được dùng để nhận diện Vương Lâm và nối với chuyện cấm chế tại Triều Tịch vực sâu.","theLucLienQuan":["Vương Lâm","Vương Nguy"],"nguon":["@c0951"]},{"id":"tien-linh-thien-canh","name":"Tiên Linh Thiên Cảnh","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Không gian trọng yếu nơi tiên phong tràn ngập, vòng bảo vệ được khôi phục và Cửu Long trận pháp hiện thế.","detail":"Trong chương này, Tiên Linh Thiên Cảnh là bối cảnh trung tâm của biến động lớn: tiên khí quét qua nhiều nơi, bốn cột sáng đông tây nam bắc nối liền thành vòng bảo vệ, trung tâm cảnh giới sụp đổ lộ ra chín tử long, rồi Cửu Long trận pháp vận chuyển để mở tòa động phủ thứ năm.","theLucLienQuan":[],"nguon":["@c0952"]},{"id":"sa-mac-mau-den-trong-dong-phu-thu-nam","name":"Sa mạc màu đen trong động phủ thứ năm","cn":"","capDo":"khac","parentId":"dong-phu-thu-nam","blurb":"Vùng hắc sa mênh mông nơi Vương Lâm xuất hiện sau khi bị tử quang đưa vào động phủ thứ năm. Bầu trời u ám, thần thức không dò ra biên giới và các thủ đoạn di chuyển bị hạn chế.","detail":"Sa mạc màu đen trải dài tới chân trời, trong phạm vi thần thức của Vương Lâm không có ai khác tồn tại. Ở đây, khí xám từ trên trời giáng xuống tấn công, thuấn di và Súc địa thành thốn không giúp thoát khỏi vị trí cũ, còn công kích trực diện khiến khí xám và gió xoáy phân hóa nhiều hơn.","theLucLienQuan":[],"nguon":["@c0953"]},{"id":"cau-go-sau-trong-dong-phu-thu-nam","name":"Cầu gỗ sâu trong động phủ thứ năm","cn":"","capDo":"khac","parentId":"dong-phu-thu-nam","blurb":"Khu vực sâu trong động phủ thứ năm, có cầu gỗ bắc qua dòng nước đen và u ảnh dữ tợn. Ma ảnh nơi cầu gỗ ngồi khoanh chân tại đây cùng bình nhỏ nút gỗ trước mặt.","detail":"Ở sâu trong động phủ thứ năm có một dòng nước đen, trên mặt nước có những u ảnh dữ tợn trôi qua. Trên cầu gỗ bắc qua dòng nước, Ma ảnh bị sương đen và ma khí bao phủ ngồi khoanh chân, trước mặt lơ lửng một bình nhỏ nút gỗ.","theLucLienQuan":[],"nguon":["@c0953"]},{"id":"dong-phu-tien-de-thanh-lam","name":"Động phủ Tiên Đế Thanh Lâm","cn":"","capDo":"khac","parentId":null,"blurb":"Động phủ của Tiên Đế Thanh Lâm, nơi Vương Lâm đang thăm dò và gặp nhiều nguy cơ khó lường.","detail":"Chương này xác nhận bên trong động phủ có khu hoang mạc cát đen với gió xoáy hủy diệt, sát cơ phản ứng với thần thức và quy tắc cấm bay, khiến Vương Lâm phải bỏ tâm thế chủ quan và luôn cảnh giác.","theLucLienQuan":[],"nguon":["@c0954"]},{"id":"hoang-mac-cat-den","name":"Hoang mạc cát đen","cn":"","capDo":"khac","parentId":"toa-dong-phu-thu-nam","blurb":"Không gian hoang mạc vô biên khiến Vương Lâm bị vây nửa năm, không rõ phương hướng và không phân biệt ngày đêm.","detail":"Hoang mạc cát đen là nơi Vương Lâm bị giam hãm trong động phủ thứ năm. Nơi này có nhiều đạo thần thức lạ quét qua, ma khí tự ngưng tụ trên người hắn và khi bị bóp nát có thể tạo trạng thái hư không tạm thời, giúp thần thức của hắn hoạt động trong phạm vi nhất định.","theLucLienQuan":[],"nguon":["@c0955"]},{"id":"thap-den","name":"Tháp đen","cn":"","capDo":"khac","parentId":"hoang-mac-cat-den","blurb":"Tháp đen là công trình trung tâm trong hoang mạc cát đen. Lão già ma khí chạy về đây cầu cứu, ba mươi mốt người áo đen bay ra từ đây và Minh Hải xuất hiện trên đỉnh tháp.","detail":"Trong chương 957, tháp đen là nơi hội tụ các thần thức còn lại sau khi lão già ma khí bị truy sát. Từ tháp bay ra ba mươi mốt người áo đen, và trên đỉnh tháp, Minh Hải tự xưng Ma phó Ngũ Hành Thủy Tán Ma, mở đầu trận giao chiến với Vương Lâm.","theLucLienQuan":["Ngũ Hành Thủy Tán Ma"],"nguon":["@c0957"]},{"id":"the-gioi-trong-binh","name":"Thế giới trong bình","cn":"","capDo":"gioi-nho","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Thế giới trong bình là tầng thứ nhất động phủ Tiên Đế, nằm trong một cái bình chí bảo. Nơi này có chín mươi chín giới và bị cát đen bao phủ do ảnh hưởng thần niệm cùng Đại Mạc Cô Yên.","detail":"Minh Hải xác nhận nơi Vương Lâm đang ở là thế giới trong bình, vốn do Tiên Đế lấy tiên khí biến hóa tiên linh. Sau khi Tiên Đế trọng thương, thần niệm sụp đổ và bị thần thông Đại Mạc Cô Yên ảnh hưởng, nơi này hóa thành cát đen; đồng bạn của Vương Lâm bị phân tán tới các nơi khác nhau trong chín mươi chín giới.","theLucLienQuan":["Tiên Đế hệ"],"nguon":["@c0959"]},{"id":"tang-thu-nhat-dong-phu-tien-de","name":"Tầng thứ nhất động phủ Tiên Đế","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Tầng thứ nhất động phủ Tiên Đế chính là thế giới trong bình được Minh Hải hé lộ. Đây là khu vực chứa tiên linh biến hóa, về sau bị biến thành cát đen.","detail":"Chương xác nhận bối cảnh chiến đấu của Vương Lâm và Minh Hải là tầng thứ nhất động phủ Tiên Đế. Nơi này nằm trong cái bình chí bảo của Tiên Đế, có cấu trúc nhiều giới và chịu ảnh hưởng nặng của Đại Mạc Cô Yên.","theLucLienQuan":["Tiên Đế hệ"],"nguon":["@c0959"]},{"id":"chin-muoi-chin-gioi","name":"Chín mươi chín giới","cn":"","capDo":"khac","parentId":"the-gioi-trong-binh","blurb":"Chín mươi chín giới là cấu trúc bên trong thế giới trong bình. Mỗi giới đều có cát đen và các đồng bạn của Vương Lâm bị chia tán tới nhiều nơi khác nhau.","detail":"Theo Minh Hải, thế giới trong bình không chỉ là một không gian đơn lẻ mà gồm chín mươi chín giới. Việc phân tán các đồng bạn của Vương Lâm cho thấy nơi này là một tầng không gian phức tạp, gắn với khảo nghiệm và nguy hiểm riêng.","theLucLienQuan":["Tiên Đế hệ"],"nguon":["@c0959"]},{"id":"dai-dien-ma-khi","name":"Đại điện ma khí","cn":"","capDo":"khac","parentId":null,"blurb":"Đại điện ma khí là nơi xuất hiện ở cuối thông đạo do U Minh Dẫn Lộ mở ra. Bên trong ma khí lượn lờ và có một người ngồi trên ghế lớn.","detail":"Khi Vương Lâm nghiền các đầu người chứa ma khí để thi triển U Minh Dẫn Lộ trong tháp đen, thông đạo mở tới một không gian mới. Hắn nhìn thấy một tòa đại điện đầy ma khí, nơi có một người bí ẩn đang ngồi trên ghế lớn.","theLucLienQuan":[],"nguon":["@c0959"]},{"id":"dai-dien-cuoi-thong-dao","name":"Đại điện cuối thông đạo","cn":"","capDo":"khac","parentId":"the-gioi-trong-binh","blurb":"Đại điện nằm ở cuối thông đạo do U Minh Dẫn Lộ mở ra nhưng bị quấy nhiễu. Nơi này tràn ma khí cực kỳ tinh thuần và có bóng người thần bí ngồi trên ngai vàng.","detail":"Khi Vương Lâm thi triển U Minh Dẫn Lộ, thông đạo không đưa hắn ra ngoài mà dẫn sâu hơn tới một đại điện chìm trong ma khí. Bóng người trên ngai vàng tại đây ném ra tinh thể hình thoi màu vàng trước khi thông đạo sụp đổ.","theLucLienQuan":[],"nguon":["@c0960"]},{"id":"ngon-thap-den-cua-vuong-lam","name":"Ngọn tháp đen của Vương Lâm","cn":"","capDo":"khac","parentId":"hoang-mac-cat-den","blurb":"Điểm trú ban đầu của Vương Lâm giữa biển lửa trong hoang mạc cát đen. Hắn nhiều lần lui vào đây để hấp thụ lửa trời trước khi đủ sức rời xa.","detail":"Trong chương 961, Vương Lâm từ ngọn tháp đen nhiều lần ra ngoài lấy lửa trời từ biển lửa rồi dung nhập vào cơ thể. Đây là nơi hắn khởi đầu quá trình thích ứng với nhiệt lực trước khi đi sâu hơn trong hoang mạc cát đen.","theLucLienQuan":[],"nguon":["@c0961"]},{"id":"ngon-thap-den-cho-lang-thien-hau","name":"Ngọn tháp đen chỗ Lăng Thiên Hậu","cn":"","capDo":"khac","parentId":"the-gioi-trong-binh","blurb":"Một ngọn tháp đen khác trong thế giới trong bình, nơi Lăng Thiên Hậu đang tĩnh tọa khi tiếng kêu Chu Tước vang tới.","detail":"Khi tiếng kêu thức tỉnh của Chu Tước truyền khắp thế giới trong bình, Lăng Thiên Hậu đang khoanh chân trong ngọn tháp đen này. Âm thanh khiến hắn mở mắt và lộ vẻ chấn động khó tưởng tượng.","theLucLienQuan":[],"nguon":["@c0961"]},{"id":"song-nho-duoi-cau","name":"Sông nhỏ dưới cầu","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Dòng sông nhỏ dưới cầu trong động phủ Tiên Đế. Khi biển lửa từ bình bạch ngọc phun ra, nước sông bị bốc hơi và lòng sông khô nứt.","detail":"Sông nhỏ nằm dưới cầu gỗ nơi bình bạch ngọc được đặt. Sức nóng từ biển lửa làm nước sông bay hơi, lộ lòng sông khô nứt và khiến sinh vật dữ tợn trong đó hóa thành sương máu.","theLucLienQuan":["Tiên Đế"],"nguon":["@c0963"]},{"id":"tien-tri","name":"Tiên Trì","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Tiên Trì là nơi bị Tán Ma dùng thánh khí Phù Tộc vùi lấp. Bối La xác nhận đây là nơi chôn Tiên Đế Thanh Lâm và vô số tiên nhân.","detail":"Bên dưới Tiên Trì là cơn lốc xoáy khổng lồ như Quỷ Vực, có lực hút, hồn phách cắn nuốt nguyên thần và phong ấn nữ tử mờ ảo. Đây là bẫy đã được chuẩn bị từ vô số năm trước để chờ đoàn người rơi vào.","theLucLienQuan":["Phù Tộc","Cổ Ma","Tiên Giới"],"nguon":["@c0964"]},{"id":"noi-chon-thanh-lam","name":"Nơi chôn Thanh Lâm","cn":"","capDo":"khac","parentId":"tien-tri","blurb":"Nơi chôn Thanh Lâm nằm trong khu vực Tiên Trì. Tán Ma nói nơi này đã được Tháp Già chuẩn bị từ vô số năm trước để chờ đoàn người.","detail":"Đây là nơi gắn với cái chết hoặc việc mai táng Tiên Đế Thanh Lâm, đồng thời bị biến thành bẫy hiến tế Cổ Ma. Bối La cũng xác nhận nơi đây vốn là Tiên Trì, nơi chôn Thanh Lâm và vô số tiên nhân.","theLucLienQuan":["Cổ Ma","Tiên Giới"],"nguon":["@c0964"]},{"id":"con-loc-xoay-duoi-mat-dat","name":"Cơn lốc xoáy dưới mặt đất","cn":"","capDo":"khac","parentId":"tien-tri","blurb":"Cơn lốc xoáy khổng lồ lộ ra sau khi Tán Ma đạp nát mặt đất dưới Tiên Trì. Nó có lực hút mạnh, tiếng gào thét như Quỷ Vực và vô số hồn phách bên trong.","detail":"Lốc xoáy này hút Trần Đạo Tam Tử, đồng tử đầu to và nhiều nữ đệ tử vào trong. Bên trong còn có tổ phù đỏ máu, nữ tử mờ ảo bị phong ấn, cơn lốc sát khí và biển máu từ hốc mắt nàng.","theLucLienQuan":["Phù Tộc","Tiên Di Tộc","Cổ Ma"],"nguon":["@c0964"]},{"id":"bien-mau-den","name":"Biển máu đen","cn":"","capDo":"khac","parentId":"con-loc-xoay-duoi-mat-dat","blurb":"Biển máu trong cơn lốc xoáy chôn tiên, chứa sát khí, mùi tanh và hồn phách không được luân hồi.","detail":"Biển máu đen áp sát rất nhanh trong lốc xoáy, đe dọa Vương Lâm, Tư Đồ Nam, Thiên Vận Tử và Lăng Thiên Hậu. Sát khí của nó có thể làm nguyên lực trong cơ thể tu sĩ đình trệ, đồng thời là nơi thân ảnh mơ hồ bị phong ấn trỗi dậy ra tay.","theLucLienQuan":["Phù Tộc"],"nguon":["@c0965"]},{"id":"khe-lon-trong-hu-khong-phia-tren-con-loc-xoay","name":"Khe lớn trong hư không phía trên cơn lốc xoáy","cn":"","capDo":"khac","parentId":"con-loc-xoay-duoi-mat-dat","blurb":"Khe nứt hư không do Thiên Vận Tử áo xám mở khi thi triển Sát Lục Thành Giới.","detail":"Khi Thiên Vận Tử áo xám chỉ lên hư không, phía trên mọi người vang lên tiếng nổ ầm ầm và xuất hiện khe lớn. Từ khe này, vô số Sát Lục Khí tràn ra, tạo tiền đề cho Sát Lục Thao Thiên đánh xuống thân ảnh mơ hồ trong biển máu.","theLucLienQuan":[],"nguon":["@c0965"]},{"id":"tang-tien-tri","name":"Táng Tiên Trì","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Táng Tiên Trì là nơi giam giữ Thu Dao bằng sợi gân đỏ thẫm và cấm chế phân thân Thanh Lâm.","detail":"Trong chương này, Táng Tiên Trì hóa thành cơn lốc xoáy chôn tiên, bị Thu Dao dùng một trảo kéo lên khiến lốc xoáy co rút, vô số hồn phách tiên nhân gào thét lao ra. Cấm chế phân thân Thanh Lâm hiện thân tại đây để ngăn thánh tổ Thu Dao của Phù Tộc thoát khỏi phong ấn.","theLucLienQuan":["Phù Tộc","Tiên Giới"],"nguon":["@c0966"]},{"id":"con-loc-xoay-chon-tien","name":"Cơn lốc xoáy chôn tiên","cn":"","capDo":"khac","parentId":"tang-tien-tri","blurb":"Cơn lốc xoáy chôn tiên là hình thái chấn động của Táng Tiên Trì khi Thu Dao xuất hiện.","detail":"Không gian lốc xoáy này nằm bên dưới mọi người, nơi biển máu sụp đổ, Thu Dao bay lên và vô số hồn phách tiên nhân bị khuấy động khi nàng định nhấc Táng Tiên Trì khỏi mặt đất.","theLucLienQuan":["Phù Tộc"],"nguon":["@c0966"]},{"id":"tu-vong-cam-dia","name":"Tử vong cấm địa","cn":"","capDo":"vuc","parentId":"lien-minh-tinh-vuc","blurb":"Tử vong cấm địa là cách Tu Chân Liên Minh gọi những địa vực cực hiểm trong Liên Minh Tinh Vực mà họ không thể khống chế.","detail":"Các khu vực này khiến tu sĩ bình thường không được bước vào, người dưới Toái Niết không dám tùy tiện tiếp cận, còn tu sĩ bước hai đều ít nhiều biết tới mức nguy hiểm của chúng.","theLucLienQuan":["Tu Chân Liên Minh"],"nguon":["@c0967"]},{"id":"vung-dat-chu-tuoc","name":"Vùng đất Chu Tước","aliases":["Tinh vực bị thiêu đốt"],"cn":"","capDo":"vuc","parentId":"lien-minh-tinh-vuc","blurb":"Vùng đất Chu Tước là một tử vong cấm địa trong Liên Minh Tinh Vực, bao phủ bởi biển lửa tự nhiên từ thời xa xưa.","detail":"Biển lửa nơi đây không phải thần thông của Thanh Lâm mà do thiên nhiên sinh ra. Sau vô số năm thiêu đốt, trong vùng này chỉ còn chín tinh cầu dạng trăng lưỡi liềm, gọi là Chu Tước Thánh Tinh.","theLucLienQuan":["Chu Tước Thánh Tông","Tu Chân Liên Minh"],"nguon":["@c0967"]},{"id":"chu-tuoc-thanh-tinh","name":"Chu Tước Thánh Tinh","cn":"","capDo":"tinh-cau","parentId":"vung-dat-chu-tuoc","blurb":"Chu Tước Thánh Tinh là chín tinh cầu dạng trăng lưỡi liềm tồn tại trong biển lửa vùng đất Chu Tước.","detail":"Đây là địa bàn của Chu Tước Thánh Tông, nơi đặt Chu Tước Thánh Tượng và là nguồn phát sinh Chu Tước Chi Biến khiến chín cột lửa hợp thành Chu Tước Chân Linh.","theLucLienQuan":["Chu Tước Thánh Tông"],"nguon":["@c0967"]},{"id":"thanh-tinh-vi-ton","name":"Thánh Tinh Vi Tôn","cn":"","capDo":"tinh-cau","parentId":"chu-tuoc-thanh-tinh","blurb":"Thánh Tinh Vi Tôn là tinh cầu thứ nhất trong chín Chu Tước Thánh Tinh.","detail":"Trên hướng chính nam của tinh cầu này có pho Chu Tước Thánh Tượng khổng lồ, nơi các đệ tử Chu Tước Thánh Tông tu luyện và nơi biến động Chu Tước Chi Biến bùng phát rõ rệt.","theLucLienQuan":["Chu Tước Thánh Tông"],"nguon":["@c0967"]},{"id":"con-loc-xoay-dong-hai","name":"Cơn lốc xoáy Đông Hải","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Cơn lốc xoáy Đông Hải ngoài tinh không vùng đất Yêu Linh bị biến cố Táng Tiên Trì dẫn động dữ dội.","detail":"Khi Táng Tiên Trì hiện hình và sụp đổ, cơn lốc xoáy Đông Hải mở rộng điên cuồng, cuốn chết một số tu sĩ đi ngang và thu hút sự chú ý từ bên ngoài.","theLucLienQuan":[],"nguon":["@c0969"]},{"id":"ho-sau-sau-tang-tien-tri","name":"Hố sâu sau Táng Tiên Trì","cn":"","capDo":"khac","parentId":"tang-tien-tri","blurb":"Hố sâu còn lại sau khi Táng Tiên Trì sụp đổ. Đây là nơi nhóm sống sót đi ra và Tinh Ngân Điêu lao xuống vì cảm nhận khí tức bên dưới.","detail":"Sau biến cố Táng Tiên Trì, hố sâu trở thành điểm xuất hiện của Đồng tử đầu to, Trần Đạo Tam Tử và những người từng bị hút vào. Thôn nữ xinh đẹp, một nữ đệ tử và Tôn trưởng lão không đi ra, còn Tinh Ngân Điêu tự lao xuống do cảm nhận khí tức khiến nó mê muội phát cuồng.","theLucLienQuan":[],"nguon":["@c0970"]},{"id":"tinh-khong","name":"Tinh Không","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Không gian rộng lớn chứa tinh vân, thiên thạch và bụi nhỏ. Chương này hé lộ động phủ Tiên Đế Thanh Lâm nằm trong một mảng bụi cực nhỏ giữa Tinh Không.","detail":"Tinh Không được miêu tả là vô biên, có tinh vân xoay quanh, thiên thạch lướt qua và vô số bụi nhỏ. Trong một mảng bụi rất nhỏ lại ẩn chứa vùng đất Yêu Linh, Tiên Linh Thiên Cảnh và động phủ Thanh Lâm.","theLucLienQuan":[],"nguon":["@c0970"]},{"id":"mang-bui-cuc-nho-trong-tinh-khong","name":"Mảng bụi cực nhỏ trong Tinh Không","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Mảng bụi cực nhỏ giữa Tinh Không nhưng bên trong có một Càn Khôn khác. Nó chứa vùng đất Yêu Linh, Tiên Linh Thiên Cảnh và động phủ Tiên Đế Thanh Lâm.","detail":"Mảng bụi này nhỏ tới mức tu sĩ Toái Niết quét thần thức cũng khó phát giác nếu không biết trước. Bên trong nó là không gian chứa toàn bộ vùng đất Yêu Linh, Tiên Linh Thiên Cảnh và động phủ của Thanh Lâm.","theLucLienQuan":["Yêu Linh","Tiên Giới"],"nguon":["@c0970"]},{"id":"dai-dien-tim-trung-tam-dong-phu-tien-de","name":"Đại điện tím trung tâm động phủ Tiên Đế","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Đại điện tím ở trung tâm động phủ Tiên Đế, nơi có chín mươi chín giá nến tạo trận pháp. Không gian dưới lòng đất nơi đây liên hệ trực tiếp với Thanh Lâm.","detail":"Đại điện tím có chín mươi chín giá nến tạo thành trận pháp trên mặt đất. Khi hai mươi ba ngọn bị dập tắt, không gian dưới lòng đất nơi nam tử thần bí ngồi rung chuyển, mở ra việc xác nhận người ấy chính là Thanh Lâm.","theLucLienQuan":["Tiên Đế"],"nguon":["@c0970"]},{"id":"phu-gioi-map","name":"Phù Giới","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Giới do Thanh Lâm mở cho Phù Tộc khai thiên lập địa theo lời hồi ức của ông. Sau đó ông phát hiện Phù Tộc lấy tiên hồn để mở Thánh Phù.","detail":"Thanh Lâm kể từng mở một giới cho Phù Tộc để họ khai thiên lập địa. Nhưng khi tận mắt thấy Phù Tộc lấy tiên hồn trong Tiên Giới để mở Thánh Phù, quan hệ giữa hai bên chuyển thành đại chiến.","theLucLienQuan":["Phù Tộc","Tiên Giới"],"nguon":["@c0970"]},{"id":"vung-bien-menh-mong","name":"Vùng biển mênh mông","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Vùng biển nơi Vương Lâm tỉnh lại sau khi bị cấm chế trong khóm hoa truyền tống. Cuối chương, sóng dữ như tường thành xuất hiện ở phía xa.","detail":"Sau biến cố truyền tống, Vương Lâm đứng trên mặt biển rộng mênh mông và suy nghĩ về nữ tử yêu khí có cảm giác quen thuộc. Khi hắn đang trầm ngâm, phía cuối mặt biển xuất hiện sóng dữ gào thét lao tới như một bức tường thành.","theLucLienQuan":[],"nguon":["@c0970"]},{"id":"the-gioi-trong-mot-giot-suong","name":"Thế giới trong một giọt sương","cn":"","aliases":["Thế giới biển cả trong giọt sương","Thế giới trong một giọt sương","Cấm chế giọt sương trong khóm hoa"],"capDo":"gioi-nho","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Không gian cấm chế Vương Lâm rơi vào sau Táng Tiên Trì, bề ngoài là biển xanh nhưng bản chất là một giới trong giọt sương.","detail":"Sau khi tránh sóng dữ và kiểm tra nước không mùi, Vương Lâm xác định nơi này không phải biển thật mà là thế giới bên trong một giọt sương sớm. Không gian này thuộc hệ cấm chế trong động phủ Tiên Đế, vừa vây khốn vừa khiến người đi vào phải tiêu hao và cảnh giác.","theLucLienQuan":["Tiên Đế","Phù Tộc"],"nguon":["@c0971"]},{"id":"rung-ram-do-cam-che-dua-toi","name":"Rừng rậm do cấm chế đưa tới","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Vùng rừng rậm âm u trong động phủ Tiên Đế, nơi nam tử thân như ngọn tháp bị cấm chế đưa tới sau biến cố Tiên Trì. Khu vực có lá mục, xương mãnh thú và nhiều xác mãnh thú bị lột da mi tâm.","detail":"Sau khi Tiên Trì sụp đổ, cấm chế đưa nam tử thân như ngọn tháp tới một vùng rừng rậm ẩm ướt âm u. Hắn ngồi tu luyện giữa nhiều xác mãnh thú bị lấy da phần mi tâm, hấp thụ thánh phù lực của tổ tiên và lĩnh hội Khô Phù Thuật.","theLucLienQuan":[],"nguon":["@c0972"]},{"id":"bien-khoi-trong-dong-phu-tien-de","name":"Biển khơi trong động phủ Tiên Đế","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Vùng biển trong động phủ Tiên Đế, nơi Vương Lâm ẩn dưới sâu sau biến cố Tiên Trì. Tại đây hắn thu Khô Phù, quan sát tinh thể màu vàng và bị Diêu Tích Tuyết công kích từ mặt biển.","detail":"Vương Lâm ở sâu trong biển khơi, thu hồi thanh đại kiếm, gỡ Khô Phù và nghiên cứu tinh thể màu vàng liên quan tới phân thân Thanh Lâm. Khi hắn chuẩn bị rời đi, thần thông từ mặt biển đánh xuống, mở màn cuộc đối đầu với Diêu Tích Tuyết.","theLucLienQuan":[],"nguon":["@c0972"]},{"id":"mat-bien-noi-dieu-tich-tuyet-xuat-hien","name":"Mặt biển nơi Diêu Tích Tuyết xuất hiện","cn":"","capDo":"khac","parentId":"bien-khoi-trong-dong-phu-tien-de","blurb":"Không trung và mặt biển nơi Diêu Tích Tuyết hiện thân trong yêu khí nồng đậm. Đây là chiến trường trực diện giữa nàng và Vương Lâm trong chương 972.","detail":"Diêu Tích Tuyết đứng trên mặt biển, bị yêu khí bao phủ, gọi Vương Lâm ra và dùng yêu khí hóa yêu long đánh xuống biển. Vương Lâm phá biển hiện thân, nhận ra nàng và đối diện ân oán cũ.","theLucLienQuan":[],"nguon":["@c0972"]},{"id":"khom-hoa-trong-dong-phu","name":"Khóm hoa trong động phủ","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Khu vực trong động phủ Tiên Đế chứa cấm chế giọt sương. Một giọt sương trên lá trong khóm hoa hóa thành thế giới biển cả mà Vương Lâm và Phong Yêu vừa phá.","detail":"Khóm hoa này nằm trong động phủ Tiên Đế và chứa cấm chế biến một giọt sương thành thế giới biển cả. Khi Vương Lâm đốt sạch giọt nước cuối cùng, thế giới cấm chế tan rã, để lộ hai người trở lại bên ngoài khóm hoa.","theLucLienQuan":["Tiên Đế"],"nguon":["@c0974"]},{"id":"tang-thu-muoi-bon-cua-phong-tien-an","name":"Tầng thứ mười bốn của Phong Tiên Ấn","cn":"","capDo":"khac","parentId":null,"blurb":"Không gian phong giữ Huyết Tổ trong Phong Tiên Ấn. Chương này Vương Lâm mở tầng này, giải cấm và cho Huyết Tổ rời đi.","detail":"Tầng thứ mười bốn là nơi Huyết Tổ bị giam giữ trong Phong Tiên Ấn. Khi gặp lại Diêu Tích Tuyết, Vương Lâm mở tầng này để Huyết Tổ ra ngoài, tuyên bố hắn không cần quay lại nữa và kết thúc đoạn nhân quả cũ.","theLucLienQuan":[],"nguon":["@c0975"]},{"id":"ho-sau-do-tang-tien-tri-luu-lai","name":"Hố sâu do Táng Tiên Trì lưu lại","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Hố sâu còn lại sau khi Táng Tiên Trì sụp đổ, hàn khí đã không còn. Vương Lâm chọn nơi này để khoét động bế quan đột phá.","detail":"Sau khi Táng Tiên Trì sụp đổ, nơi này lưu lại một hố sâu trong động phủ Tiên Đế. Vương Lâm nhảy xuống, dùng đại kiếm khoét vách đá thành cửa động, bố trí cấm chế và bế quan tại đây.","theLucLienQuan":[],"nguon":["@c0975"]},{"id":"khu-lau-cac-trong-dong-phu-tien-de","name":"Khu lầu các trong động phủ Tiên Đế","cn":"","capDo":"khac","parentId":"dong-phu-tien-de-thanh-lam","blurb":"Khu vực phía trước ngoại vi động phủ Tiên Đế, gồm nhiều lầu các hợp thành đồ hình không quy tắc. Sâu trong khu này có một gian đại điện bị sương đen bao phủ.","detail":"Khi quan sát ngoại vi động phủ Tiên Đế, Vương Lâm nhìn thấy phía trước có nhiều lầu các sắp xếp thành hình thế không quy tắc. Cảnh tượng này trùng khớp với bản đồ trong ngọc giản tiên ngọc mà hắn từng thu được.","theLucLienQuan":["Tiên Đế"],"nguon":["@c0975"]},{"id":"gian-dai-dien-trong-suong-den","name":"Gian đại điện trong sương đen","cn":"","capDo":"khac","parentId":"khu-lau-cac-trong-dong-phu-tien-de","blurb":"Gian đại điện như ẩn như hiện ở chỗ sâu trong dãy lầu các của động phủ Tiên Đế. Nơi này bị sương đen nồng đậm bao phủ, báo hiệu khu vực sâu hơn của động phủ.","detail":"Từ ngoại vi động phủ, Vương Lâm nhìn về phía sâu trong khu lầu các và thấy một gian đại điện bị sương đen nồng đậm bao phủ. Đây là dấu mốc đáng chú ý trên đường tiến sâu vào động phủ Tiên Đế.","theLucLienQuan":["Tiên Đế"],"nguon":["@c0975"]},{"id":"con-hu-tinh-vuc","name":"Côn Hư Tinh Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực gắn với Côn Hư Cảnh trong hồi thuật đại chiến với Tứ Thánh Tông.","detail":"Côn Hư Tinh Vực là bối cảnh nội chiến xưa giữa Tứ Thánh Tông, Tu Chân Liên Minh và Côn Hư Cảnh. Côn Hư Cảnh nằm trong tinh vực này và từng tham chiến nhằm nhổ cỏ tận gốc Tứ Thánh Tông.","theLucLienQuan":["Côn Hư Cảnh","Tứ Thánh Tông","Tu Chân Liên Minh"],"nguon":["@c0976"]},{"id":"dong-hang-dong-noi-vuong-lam-be-quan","name":"Động nơi Vương Lâm bế quan","cn":"","capDo":"khac","parentId":null,"blurb":"Hang động nơi Vương Lâm khoanh chân nuốt nguyên thần để đột phá.","detail":"Đây là nơi Vương Lâm ở lại tu luyện trong lúc không hay biết chiến sự bên ngoài. Khi hắn chuyển hóa nguyên lực mang hỏa diễm và xung kích Khuy Niết Hậu Kỳ, sức nóng cùng gió lốc nguyên lực phá nát hang động, để lộ hố sâu bên dưới.","theLucLienQuan":[],"nguon":["@c0976"]},{"id":"ho-sau-duoi-hang-dong-vuong-lam","name":"Hố sâu dưới hang động Vương Lâm","cn":"","capDo":"khac","parentId":"dong-hang-dong-noi-vuong-lam-be-quan","blurb":"Không gian bên dưới hang động sau khi nơi Vương Lâm bế quan sụp đổ.","detail":"Sau khi hang động bị phá nát, Vương Lâm chìm xuống hố sâu. Tại đây phân thân hắn xuất hiện giữa không trung, dấu ấn Chu Tước lượn quanh và nguyên thần rời mi tâm cùng tiếng rít Thái Cổ Lôi Long.","theLucLienQuan":[],"nguon":["@c0976"]},{"id":"cua-vao-tong-bo-tu-chan-lien-minh","name":"Cửa vào tổng bộ Tu Chân Liên Minh","cn":"","capDo":"khac","parentId":"lien-minh-tinh-vuc","blurb":"Khu vực cửa vào dẫn tới tổng bộ Tu Chân Liên Minh trong Liên Minh Tinh Vực.","detail":"Nơi này nằm giữa tinh vực đầy thiên thạch tím u ám, có một tòa nhà tròn khổng lồ cùng hơn một trăm tòa nhà nhỏ bao quanh. Từ đây có thể tiến vào không gian độc lập vốn thuộc Vũ Tiên Giới mà Tu Chân Liên Minh chiếm cứ.","theLucLienQuan":["Tu Chân Liên Minh"],"nguon":["@c0977"]},{"id":"tong-bo-tu-chan-lien-minh","name":"Tổng bộ Tu Chân Liên Minh","cn":"","capDo":"khac","parentId":"lien-minh-tinh-vuc","blurb":"Không gian độc lập làm tổng bộ của Tu Chân Liên Minh.","detail":"Tổng bộ này vốn thuộc Vũ Tiên Giới, sau bị Tu Chân Liên Minh chiếm cứ. Bên trong có một trăm bảy mươi ba tu chân tinh rất lớn hợp thành, trung tâm tồn tại vòng xoáy tím cực lớn, được Vương Lâm nhìn thấy khi tâm thần đảo qua Liên Minh Tinh Vực.","theLucLienQuan":["Tu Chân Liên Minh"],"nguon":["@c0977"]},{"id":"vong-xoay-tim-trong-tong-bo-tu-chan-lien-minh","name":"Vòng xoáy tím trong tổng bộ Tu Chân Liên Minh","cn":"","capDo":"khac","parentId":"tong-bo-tu-chan-lien-minh","blurb":"Vòng xoáy tím cực lớn nằm ở trung tâm tổng bộ Tu Chân Liên Minh.","detail":"Vòng xoáy này nằm giữa ngân hà tu chân tinh trong tổng bộ Tu Chân Liên Minh. Phía trên có tu chân tinh cuối cùng hấp thụ khí tím, nơi nam tử trung niên trong mật thất tọa thiền và được chuông đồng cảnh báo khi tâm thần Vương Lâm lướt qua.","theLucLienQuan":["Tu Chân Liên Minh"],"nguon":["@c0977"]},{"id":"chien-truong-phia-bac-lien-minh-tinh-vuc","name":"Chiến trường phía bắc Liên Minh Tinh Vực","cn":"","capDo":"khac","parentId":"lien-minh-tinh-vuc","blurb":"Chiến trường nơi tu sĩ La Thiên và Tu Chân Liên Minh đang giao chiến.","detail":"Nằm ở phía bắc Liên Minh Tinh Vực, nơi mấy vạn tu sĩ La Thiên cùng Tu Chân Liên Minh chém giết lẫn nhau. Vương Lâm thấy Viêm Lôi Tử tham chiến tại đây trong lúc tâm thần được Thiên Nghịch Châu đưa đi cảm ngộ quy tắc.","theLucLienQuan":["La Thiên tu sĩ","Tu Chân Liên Minh"],"nguon":["@c0977"]},{"id":"tinh-cau-mau-nau-cam-dia","name":"Tinh cầu màu nâu cấm địa","cn":"","capDo":"tinh-cau","parentId":"lien-minh-tinh-vuc","blurb":"Tinh cầu màu nâu chứa Truyền Tống Trận thông tới Côn Hư Cảnh.","detail":"Tinh cầu này đầy tử khí, linh khí thưa thớt, trong phạm vi trăm vạn dặm không có tu sĩ lui tới. Bên trong nó ẩn một Truyền Tống Trận cực lớn, là lối thông tới Côn Hư Cảnh, tu chân quốc cấp chín trong Tu Chân Liên Minh.","theLucLienQuan":["Tu Chân Liên Minh","Côn Hư"],"nguon":["@c0977"]},{"id":"con-hu-canh","name":"Côn Hư Cảnh","cn":"","capDo":"gioi-nho","parentId":"lien-minh-tinh-vuc","blurb":"Tu chân quốc cấp chín thần bí trong Tu Chân Liên Minh.","detail":"Côn Hư Cảnh là một đại lục tự thành giữa trời đất, được xem là thánh địa của phần lớn tu sĩ Liên Minh Tinh Vực. Vương Lâm tiến vào nơi này bằng tâm thần qua tinh cầu màu nâu, bị lão già bên hồ phát hiện, rồi nhìn thấy Chu Như cùng nữ tử áo lam tuyệt mỹ.","theLucLienQuan":["Côn Hư","Tu Chân Liên Minh"],"nguon":["@c0977"]},{"id":"dinh-nui-trong-con-hu-canh","name":"Đỉnh núi trong Côn Hư Cảnh","cn":"","capDo":"khac","parentId":"con-hu-canh","blurb":"Đỉnh núi nơi Chu Như xuất hiện trong Côn Hư Cảnh.","detail":"Trên đỉnh núi này, Chu Như ngồi cùng con hổ đen bên cạnh, mang tâm trạng đau khổ muốn rời đi. Nữ tử áo lam tuyệt mỹ xuất hiện tại đây, được Chu Như gọi là sư tôn, khiến tâm thần Vương Lâm dừng lại và thức tỉnh khỏi trạng thái minh ngộ.","theLucLienQuan":["Côn Hư"],"nguon":["@c0977"]},{"id":"dong-phu-tien-de","name":"Động phủ Tiên Đế","cn":"","capDo":"khac","parentId":null,"blurb":"Động phủ Tiên Đế là bối cảnh Vương Lâm đang thăm dò. Ở chương này hắn định dựa vào bản đồ ngọc giản đi tiếp nhưng bị Tinh Ngân Điêu dẫn xuống hố sâu.","detail":"Vương Lâm xác định trước mắt vẫn đang ở trong động phủ Tiên Đế và dự định theo bản đồ trong ngọc giản để tiếp tục thăm dò. Diễn biến rẽ sang hố sâu khi Tinh Ngân Điêu phản ứng với nơi bên dưới Táng Tiên Trì.","theLucLienQuan":["Tiên Đế"],"nguon":["@c0978"]},{"id":"ho-sau-duoi-tang-tien-tri","name":"Hố sâu dưới Táng Tiên Trì","cn":"","capDo":"khac","parentId":"tang-tien-tri","blurb":"Hố sâu dưới Táng Tiên Trì là nơi Vương Lâm đi xuống theo Tinh Ngân Điêu. Bên dưới có khí lạnh dày, băng phủ như kiếm và một ánh mắt bí ẩn nhìn lên.","detail":"Vương Lâm phá vách đất để tới nơi bản tôn, rồi sau đó theo Tinh Ngân Điêu tiếp tục xuống sâu trong hố. Càng xuống dưới khí lạnh càng dày, vách hố phủ băng như kiếm; tại đây Vương Lâm cảm nhận một ánh mắt như xuyên qua mọi ngăn cách rơi lên người mình.","theLucLienQuan":[],"nguon":["@c0978"]},{"id":"day-ho-sau-bang-phong","name":"Đáy hố sâu băng phong","cn":"","capDo":"khac","parentId":"ho-sau-duoi-tang-tien-tri","blurb":"Không gian băng phong dưới đáy hố sâu nơi Vương Lâm phát hiện đầu lâu Cổ Thần. Nơi này có nhiều sông băng, xác chết bị đóng băng và vết tích lực lượng chặt đầu Cổ Thần.","detail":"Đáy hố sâu là một thế giới băng giá nằm bên dưới hố sâu, nơi thân thể Vương Lâm chìm xuống và thấy vô số xác chết bị đóng băng trong tư thế trước khi chết. Ở trung tâm là đầu lâu Cổ Thần khổng lồ khoảng trăm trượng bị băng phong, cổ có vết chém chỉnh tề và sâu trong miệng vết thương có kết tinh đỏ đậm còn lưu lại khí tức lực lượng năm xưa.","theLucLienQuan":["Bộ tộc Cổ Thần"],"nguon":["@c0979"]},{"id":"ho-sau-trong-tang-bang","name":"Hố sâu trong tầng băng","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Khu vực hố sâu có đầu Cổ Thần bị băng bao phủ, phía trên là nhiều sông băng đan xen chỉ còn khe hở vặn vẹo để đi qua.","detail":"Đây là nơi Vương Lâm phá băng để đoạt thanh thiết kiếm trong đầu Cổ Thần. Sau khi vật hình người trong màn sương hồng gầm lên, băng trên vách hố nứt vỡ, các xác chết trong băng bị hồng quang bao phủ như sống lại.","theLucLienQuan":["Cổ Thần"],"nguon":["@c0980"]},{"id":"rung-truc-cam-che","name":"Rừng trúc cấm chế","cn":"","capDo":"khac","parentId":"tang-thu-nhat-dong-phu-tien-de","blurb":"Khu rừng trúc trong tầng thứ nhất động phủ Tiên Đế, nơi Vương Lâm lợi dụng cấm chế để thoát khỏi vật hình người truy kích.","detail":"Rừng trúc chứa cấm chế mạnh nhưng Vương Lâm nhờ bản đồ ngọc giản nên có thể đi vào mà không kích phát. Hắn dẫn vật hình người nhảy theo vào rừng, khiến đối phương biến mất trong hào quang cấm chế, qua đó tạm thời thoát khỏi truy sát.","theLucLienQuan":[],"nguon":["@c0981"]},{"id":"cung-dien-trung-tam-trong-man-suong-den","name":"Cung điện trung tâm trong màn sương đen","cn":"","capDo":"khac","parentId":"tang-thu-nhat-dong-phu-tien-de","blurb":"Vị trí trung tâm của tầng thứ nhất động phủ Tiên Đế, nằm sau màn sương đen và liên quan tới lối đi xuống tầng thứ hai.","detail":"Theo bản đồ ngọc giản, muốn từ tầng thứ nhất tiến vào tầng thứ hai cần tới cung điện ở trung tâm. Khu vực này bị màn sương đen ngăn cách, muốn bước vào phải xử lý mắt cấm chế tương ứng trong tầng thứ nhất.","theLucLienQuan":[],"nguon":["@c0981"]},{"id":"lau-cac-mat-cam-che","name":"Lầu các mắt cấm chế","cn":"","capDo":"khac","parentId":"tang-thu-nhat-dong-phu-tien-de","blurb":"Một lầu các hai tầng trong tầng thứ nhất, là mắt cấm chế cần mở để có cơ hội tiến vào màn sương đen.","detail":"Bên ngoài lầu các trông bình thường, nhưng theo bản đồ ngọc giản lại là điểm mấu chốt của cấm chế thông tới khu vực màn sương đen. Khi Vương Lâm tới nơi, cấm chế tại lầu các đã bị phá không lâu, cho thấy có người khác cũng nắm được cách tiến vào trung tâm tầng thứ nhất.","theLucLienQuan":[],"nguon":["@c0981"]},{"id":"dinh-ta-goc-dong-bac","name":"Đỉnh tạ góc đông bắc","cn":"","capDo":"khac","parentId":"tang-thu-nhat-dong-phu-tien-de","blurb":"Đỉnh tạ ở góc đông bắc tầng thứ nhất, nơi hắc y nam tử và thôn cô mỹ phụ tranh đoạt truyền tống trận bên trong.","detail":"Đỉnh tạ này che giấu một truyền tống trận được nhận định là thông tới không gian trữ vật. Hắc y nam tử và thôn cô mỹ phụ giao thủ quanh nơi này nhưng đều tránh gây động tĩnh lớn; sau đó Vương Lâm đi tới và được đề nghị cùng tiến vào, chia đồ vật thành ba phần.","theLucLienQuan":[],"nguon":["@c0981"]},{"id":"man-suong-den-trung-tam-tang-thu-nhat","name":"Màn sương đen trung tâm tầng thứ nhất","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Khu vực ma khí nồng đậm nằm trước đại điện tầng thứ nhất của động phủ Tiên Đế.","detail":"Vương Lâm và hắc y nam tử buộc phải xông vào màn sương đen trung tâm vì tiếng rít của vật hình người phía sau đã áp sát. Nơi này có ma khí nồng đậm, khiến hắc y nam tử phải nhắc Vương Lâm cẩn thận.","theLucLienQuan":["Tiên Đế"],"nguon":["@c0982"]},{"id":"dai-dien-trong-tang-tien-tri","name":"Đại điện trong Táng Tiên Trì","cn":"","capDo":"khac","parentId":"tang-tien-tri","blurb":"Không gian đại điện có cấm chế, hai pho tượng và cơ quan ánh tím trong Táng Tiên Trì.","detail":"Đại điện là nơi cấm chế bị phá, Hư Không Tử và thôn cô tiến vào, đồng thời cũng là nơi Vương Lâm mượn lực công kích để rơi tới vị trí trung tâm ánh mắt hai pho tượng. Hai pho tượng trong đại điện phát ánh tím và tạo lốc xoáy, gợi liên hệ tới lối vào tầng thứ hai.","theLucLienQuan":[],"nguon":["@c0983"]},{"id":"tang-thu-hai-tang-tien-tri","name":"Tầng thứ hai Táng Tiên Trì","cn":"","capDo":"khac","parentId":"tang-tien-tri","blurb":"Tầng tiếp theo mà Vương Lâm tìm cách tiến vào trong Táng Tiên Trì.","detail":"Vương Lâm không thấy lối vào tầng thứ hai rõ ràng, nhưng suy đoán lối đi liên quan tới hai pho tượng trong đại điện. Ánh tím và lốc xoáy từ hai pho tượng cho thấy cơ chế dẫn tới tầng này đang được kích hoạt.","theLucLienQuan":[],"nguon":["@c0983"]},{"id":"di-tich-vien-co","name":"Di tích viễn cổ","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi các lão quái Toái Niết tìm kiếm pháp bảo cao tầng vượt Tiên bảo.","detail":"Theo ký ức của thôn cô xinh đẹp về lời trưởng bối, tu sĩ bước thứ hai, nhất là Toái Niết, thường ngược dòng thời gian tìm di tích viễn cổ để kiếm loại pháp bảo cấp Không vượt Tiên bảo.","theLucLienQuan":[],"nguon":["@c0985"]},{"id":"tang-thu-hai-dong-phu-tien-de","name":"Tầng thứ hai động phủ Tiên Đế","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Tầng nơi Vương Lâm tìm tới đại điện trung tâm có chín đế nến bằng đá. Tại đây hắn phát hiện kiếm khí Chu Dật và mở lối lên tầng thứ ba.","detail":"Tầng thứ hai động phủ Tiên Đế có đại điện trung tâm với chín đế nến bằng đá. Vương Lâm nhận ra dấu vết di động quanh đế nến chỉ là mê hoặc, phát hiện kiếm khí Chu Dật lưu lại và châm lửa chín đế nến để truyền lên tầng thứ ba; nhóm Hư Không Tử cũng tới sau nhưng bị chậm lại.","theLucLienQuan":["Tiên giới"],"nguon":["@c0986"]},{"id":"tang-thu-ba-dong-phu-tien-de","name":"Tầng thứ ba động phủ Tiên Đế","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Tầng mà Vương Lâm được truyền tới sau khi mở cơ quan chín đế nến ở tầng thứ hai. Chu Dật được suy đoán từng tiến vào nơi này.","detail":"Tầng thứ ba động phủ Tiên Đế là đích đến sau khi cơ quan chín đế nến ở tầng thứ hai được kích hoạt. Kiếm khí Chu Dật ở tầng trước khiến Vương Lâm suy đoán Chu Dật đã từng qua đây.","theLucLienQuan":["Tiên giới"],"nguon":["@c0986"]},{"id":"tang-thu-sau-dong-phu-tien-de","name":"Tầng thứ sáu động phủ Tiên Đế","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Tầng Vương Lâm tới sau hai tháng vượt động phủ. Nơi này có lầu các, giả sơn, sông nhỏ và hai điểm truyền tống không gian trữ vật, trong đó một nơi cất Tiên đan Thần dược.","detail":"Tầng thứ sáu động phủ Tiên Đế có khu vực lầu các bao quanh, giả sơn và sông nhỏ tạo thành khung cảnh thanh bình. Bản đồ ngọc giản cho biết nơi này có hai điểm truyền tống tới không gian trữ vật; một điểm chứa nhiều Tiên đan Thần dược mà Vương Lâm buộc phải tìm lấy để hồi phục nguyên lực và nguyên thần.","theLucLienQuan":["Tiên giới"],"nguon":["@c0986"]},{"id":"noi-cat-chua-linh-dan-dieu-duoc","name":"Nơi cất chứa linh đan diệu dược","cn":"","aliases":["Nơi cất chứa đan dược của Tiên Đế"],"capDo":"khac","parentId":"tang-thu-sau-dong-phu-tien-de","blurb":"Khu vực chứa đan dược trong tầng sáu động phủ Tiên Đế, là mục tiêu Vương Lâm hướng tới khi thương thế chưa hồi phục.","detail":"Theo suy đoán của Vương Nguy và ghi chép trong địa đồ ngọc giản, khu vực này nằm sau phòng luyện đan và truyền tống điểm. Vương Lâm tìm tới đây vì đan dược có ý nghĩa quan trọng đối với trạng thái suy yếu của hắn.","theLucLienQuan":["Tiên Đế"],"nguon":["@c0987"]},{"id":"phong-luyen-dan","name":"Phòng luyện đan","cn":"","aliases":["Đan phòng"],"capDo":"khac","parentId":"tang-thu-sau-dong-phu-tien-de","blurb":"Đan phòng trong tầng sáu động phủ Tiên Đế, bên ngoài có cấm chế bị cải biến tinh vi.","detail":"Theo địa đồ ngọc giản, bên trong phòng luyện đan có truyền tống điểm dẫn tới nơi cất chứa đan dược. Cấm chế trước đan phòng có sai khác so với bản đồ và được cải biến hòa hợp gần như hoàn mỹ; cuối chương, Chu Dật xuất hiện từ bên trong phòng này.","theLucLienQuan":["Tiên Đế"],"nguon":["@c0987"]},{"id":"dan-phong","name":"Đan phòng","cn":"","capDo":"khac","parentId":"tang-thu-sau-dong-phu-tien-de","blurb":"Đan phòng là nơi Vương Lâm tìm đan dược chữa thương tại tầng thứ sáu động phủ Tiên Đế. Cấm chế bên ngoài do Vân Tiên đạo lữ kiểm soát.","detail":"Đan dược trong đan phòng phần lớn đã bị Vân Tiên đạo lữ lấy đi, phần còn lại chủ yếu hữu dụng với linh thể. Trong chương này Vương Nguy vung tay khiến cấm chế bên ngoài đan phòng biến mất rồi lấy nhiều đợt đan dược giao cho Vương Lâm.","theLucLienQuan":["Vân Tiên đạo lữ"],"nguon":["@c0988"]},{"id":"tang-thu-sau-tien-phu","name":"Tầng thứ sáu Tiên phủ","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Không gian chính của chương, nơi Bối La, Vân Tiên đạo lữ, Vương Lâm và các nhóm tu sĩ khác tụ tập trước khi tiến sâu hơn.","detail":"Tầng thứ sáu Tiên phủ có hệ thống cấm chế do Hồ Quyên khống chế, màn sương đen trung tâm và cung điện dẫn tới ba tầng sau. Đây là nơi Bối La chuyển thế đối đầu thành hợp tác tạm thời, Vương Lâm nhận Thanh đan và Hư Không Tử bị đẩy vào thế nguy hiểm.","theLucLienQuan":["Vân Tiên đạo lữ","Tu Chân Liên Minh","Cổ Yêu"],"nguon":["@c0989"]},{"id":"tang-thu-tu-tien-phu","name":"Tầng thứ tư Tiên phủ","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Khu vực Bối La từng ác đấu với Vân Tiên đạo lữ và bị cấm chế vây khốn nhiều tháng.","detail":"Sau khi rời Táng Thiên Trì, Bối La từng gặp Vương Nguy và Hồ Quyên ở tầng thứ tư Tiên phủ. Hai bên giao tranh, Vân Tiên đạo lữ dùng cấm chế vây hắn mấy tháng, khiến hắn kiêng dè phối hợp của họ.","theLucLienQuan":["Vân Tiên đạo lữ","Cổ Yêu"],"nguon":["@c0989"]},{"id":"tang-thien-tri","name":"Táng Thiên Trì","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Địa điểm được nhắc trong lộ trình trước đó của Bối La trước khi hắn bị Vân Tiên đạo lữ vây ở tầng thứ tư.","detail":"Táng Thiên Trì là nơi Bối La từng rời khỏi trước khi gặp Vương Nguy và Hồ Quyên ở tầng thứ tư Tiên phủ. Chi tiết này nối mạch di chuyển của hắn trong Tiên phủ.","theLucLienQuan":["Cổ Yêu"],"nguon":["@c0989"]},{"id":"ba-tang-sau-tien-phu","name":"Ba tầng sau Tiên phủ","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Khu vực được Vương Nguy nói là tẩm cung bế quan của Ân sư Thanh Lâm, cần chờ thêm người trước khi tiến vào.","detail":"Ba tầng sau Tiên phủ nằm sau cung điện trong màn sương đen tầng sáu. Vương Nguy cho biết đây là tẩm cung bế quan của Thanh Lâm, hiện chưa rõ biến hóa nên nhóm cường giả dừng lại chờ thêm lực lượng.","theLucLienQuan":["Tiên Đế","Vân Tiên đạo lữ"],"nguon":["@c0989"]},{"id":"dai-dien","name":"Đại điện","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Không gian giao chiến trong Tiên Đế động phủ ở chương 990.","detail":"Đại điện là nơi Hư Không Tử bị nhóm Vương Lâm, Vương Nguy, Bối La và Chu Dật gây áp lực. Cuối chương, Thiên Vận Tử, Lăng Thiên Hậu và hồ lô lão giả cũng tiến vào đây, khiến cục diện biến động.","theLucLienQuan":["Tu Chân Liên Minh"],"nguon":["@c0990"]},{"id":"tang-thu-bay-tien-phu","name":"Tầng thứ bảy của Tiên phủ","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Tầng thứ bảy của Tiên phủ đã biến thành một không gian biển lửa, khác hẳn địa đồ ngọc giản và sáu tầng trước.","detail":"Sau khi nhóm tu sĩ truyền tống xuống, tầng thứ bảy hiện ra với núi lửa phun trào, dung nham, hắc khí, mặt đất nứt vỡ và hỏa nguyên lực nồng đậm. Vương Lâm và Hồ Quyên đều nhận ra biến hóa này không phù hợp với hiểu biết ban đầu về tầng bảy.","theLucLienQuan":[],"nguon":["@c0991"]},{"id":"ngon-nui-lua-tang-bay","name":"Ngọn núi lửa tầng bảy","cn":"","capDo":"khac","parentId":"tang-thu-bay-tien-phu","blurb":"Ngọn núi lửa ở tầng bảy là trung tâm dị biến của không gian biển lửa, nơi cửa vào tầng tám được xác định nằm bên trong.","detail":"Ngọn núi lửa phun trào dung nham và hỏa nguyên lực mãnh liệt. Vương Lâm phán đoán nó không phải vật tự nhiên sinh ra tại tầng bảy mà giống như bị người dùng thần thông dời tới đặt ở đây; Hồ Quyên cũng nhận định nhập khẩu tiến vào tầng thứ tám nằm trong lòng ngọn núi lửa này.","theLucLienQuan":[],"nguon":["@c0991"]},{"id":"day-ngon-nui-lua","name":"Đáy ngọn núi lửa","cn":"","capDo":"khac","parentId":"ngon-nui-lua-tang-bay","blurb":"Đáy ngọn núi lửa là khu vực biển dung nham đỏ sậm, khói đen và sóng nhiệt bao phủ, đồng thời dẫn tới cung điện cửa vào tầng tám.","detail":"Khi Vương Lâm xuống sâu, bên dưới ngọn núi lửa hiện ra biển dung nham đỏ sậm, nhiệt khí cuồn cuộn và khói đen không ngừng bốc lên. Tại vách đá nơi đáy núi lửa có một cung điện được khảm vào, trở thành vị trí mọi người tập trung để phá phong ấn.","theLucLienQuan":[],"nguon":["@c0991"]},{"id":"cung-dien-cua-vao-tang-thu-tam","name":"Cung điện cửa vào tầng thứ tám","cn":"","capDo":"khac","parentId":"day-ngon-nui-lua","blurb":"Cung điện ở đáy núi lửa là cửa vào tầng thứ tám, đại môn bị chữ “Ma” bằng máu đen phong ấn.","detail":"Cung điện này giống các cửa nhập khẩu ở những tầng trước của Tiên phủ, nhưng trên đại môn có chữ “Ma” bằng máu đen ẩn chứa phong ấn lực cực mạnh. Các lão quái nhiều lần công kích không thành, cuối cùng nhờ một kích của Bối La liên hợp với thần thông của mọi người khiến chữ “Ma” sụp đổ, đại môn mở ra nhưng lập tức phát sinh biến cố.","theLucLienQuan":[],"nguon":["@c0991"]},{"id":"tang-thu-tam","name":"Tầng thứ tám","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Không gian tầng thứ tám của động phủ Tiên Đế, nơi cung điện trong núi lửa mở ra và phát sinh biến cố lớn.","detail":"Sau khi chữ “Ma” tan đi và đại môn mở ra, tầng này bùng phát dung nham, khói đen che trời, quan tài đỏ nổi lên và hỏa long xuất hiện, kéo cung điện cùng nhiều tu sĩ xuống sâu dưới biển dung nham.","theLucLienQuan":[],"nguon":["@c0992"]},{"id":"nui-lua-tang-thu-tam","name":"Núi lửa tầng thứ tám","cn":"","capDo":"khac","parentId":"tang-thu-tam","blurb":"Ngọn núi lửa trong tầng thứ tám, nơi đại môn cung điện mở ra giữa biến động dung nham.","detail":"Khi đại môn mở, dung nham bên dưới núi lửa đảo lộn dữ dội, nhiệt độ tăng vọt, khói đen phun lên che kín bầu trời. Đây là trung tâm biến cố khiến quan tài đỏ và hỏa long xuất hiện.","theLucLienQuan":[],"nguon":["@c0992"]},{"id":"dai-dien-trong-nui-lua-tang-thu-tam","name":"Đại điện trong núi lửa tầng thứ tám","cn":"","capDo":"khac","parentId":"nui-lua-tang-thu-tam","blurb":"Cung điện nằm trong núi lửa tầng thứ tám, mục tiêu các tu sĩ tranh nhau tiến vào.","detail":"Sau khi cửa mở, Bối La, Vương Nguy, Hồ Quyên, Thiên Vận Tử và những người khác tìm cách vào đại điện. Về sau hỏa long nuốt cả cung điện xuống sâu dưới biển dung nham, bên ngoài bị dung nham bao phủ nhưng bên trong vẫn tồn tại.","theLucLienQuan":[],"nguon":["@c0992"]},{"id":"bien-dung-nham-duoi-nui-lua-tang-thu-tam","name":"Biển dung nham dưới núi lửa tầng thứ tám","cn":"","capDo":"khac","parentId":"nui-lua-tang-thu-tam","blurb":"Biển dung nham sâu dưới núi lửa tầng thứ tám, chứa hỏa nguyên lực nồng đậm.","detail":"Sau khi hỏa long kéo đại điện xuống sâu, Vương Lâm xuất hiện bên ngoài điện trong khu vực này. Hắn nhờ Chu Tước giác tỉnh mà không bị thương, hấp thu hỏa nguyên lực trong nhiều tháng rồi dừng lại khi cảm nhận linh thể kỳ dị trong dung nham.","theLucLienQuan":[],"nguon":["@c0992"]},{"id":"dung-nham-tang-thu-tam","name":"Dung nham","cn":"","capDo":"khac","parentId":"tang-thu-tam","blurb":"Vùng dung nham nguy hiểm nơi Vương Lâm áp sát bọt khí chứa phấn y nữ tử và Thôn cô mỹ phụ.","detail":"Tại vùng dung nham này, Thôn cô mỹ phụ hôn mê trong bọt khí và bị hỏa độc đe dọa. Nếu bọt khí vỡ, nàng sẽ bị dung nham vây ngập khiến tình trạng càng nguy hiểm.","theLucLienQuan":["Côn Hư chi cảnh"],"nguon":["@c0993"]},{"id":"cung-dien-trung-tam-tang-tam","name":"Cung điện trung tâm tầng tám","cn":"","capDo":"khac","parentId":"tang-thu-tam","blurb":"Cung điện nằm ở vị trí trung tâm tầng tám Tiên phủ. Nó bị một chưởng của Vương Lâm phá hủy một nửa, để lộ chín mươi chín giá nến bên trong.","detail":"Trong trận Vương Lâm đối đầu Cổ Ma, một chưởng kinh thiên xuyên qua màn sương đen, phá sập các lầu các rồi đánh vào cung điện trung tâm, khiến công trình này bị hủy mất một nửa và lộ ra bố trí chín mươi chín giá nến.","theLucLienQuan":[],"nguon":["@c0994"]},{"id":"tien-phu-tang-tam","name":"Tiên phủ tầng tám","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Tiên phủ tầng tám là nơi có đại điện trung tâm bị phá hủy một nửa và trận nến chín mươi chín cây. Từ đây Vương Lâm và Lăng Thiên Hầu mở đường vào tầng chín.","detail":"Sau khi Vương Lâm mở thông đạo bằng chưởng ấn, hai người trở lại đại điện trung tâm tầng tám. Nơi này còn các cây nến dùng để hợp thành quang viên, mở nhập khẩu vào tầng cuối Tiên phủ.","theLucLienQuan":["Tiên phủ"],"nguon":["@c0995"]},{"id":"tien-phu-tang-chin","name":"Tiên phủ tầng chín / tầng cuối cùng","cn":"","capDo":"khac","parentId":"tien-phu","blurb":"Tiên phủ tầng chín là tầng cuối, không lớn và gần như chỉ có đại điện. Đây là chiến trường giữa các tu sĩ với vô số ma ảnh, đồng thời là nơi Tháp Già tuyên bố sắp hoàn thành đoạt xá.","detail":"Khi Vương Lâm và Lăng Thiên Hầu tiến vào, tầng cuối hiện ra với đại điện giống các tầng trước và chiến trường ma ảnh dữ dội bên ngoài. Các tu sĩ đều bị thương, còn trong đại điện có bóng dáng ngồi trên ghế với quang điểm mi tâm bị hắc khí công kích.","theLucLienQuan":["Cổ Ma / mạch Cổ Ma","Tiên phủ"],"nguon":["@c0995"]},{"id":"dai-dien-tang-chin","name":"Đại điện tầng chín","cn":"","capDo":"khac","parentId":"tien-phu-tang-chin","blurb":"Đại điện tầng chín là trung tâm của tầng cuối Tiên phủ. Bên trong có bóng dáng ngồi trên ghế, còn bên ngoài là chiến trường ma ảnh.","detail":"Đại điện này giống tám tầng trước. Trong màn sương đen, một bóng dáng ngồi trên ghế, mi tâm chỉ còn một quang điểm bị hắc khí vô tận công kích như muốn cắn nuốt.","theLucLienQuan":["Cổ Ma / mạch Cổ Ma"],"nguon":["@c0995"]},{"id":"dai-dien-tang-tam","name":"Đại điện tầng tám","cn":"","capDo":"khac","parentId":"tang-thu-tam","blurb":"Đại điện ở tầng tám nơi ngọn nến liên quan đến thân thể Thanh Sương bị tác động khi các đại thần thông va chạm ở tầng chín.","detail":"Trong biến cố công phá ma vụ tầng chín, cảnh tượng tại tầng tám bị quấy nhiễu: ngọn nến trong đại điện lóe lên rồi tắt, quang mang trên mi tâm nam tử tiêu tan, ma khí tràn vào linh đài và mở đường cho Cổ Ma Tháp Già chi phối thân thể Thanh Sương.","theLucLienQuan":[],"nguon":["@c0996"]},{"id":"lien-minh-tinh-vuc-bac-bo","name":"Liên Minh Tinh Vực Bắc Bộ","cn":"","capDo":"vuc","parentId":"lien-minh-tinh-vuc","blurb":"Khu vực chiến trường phía bắc Liên Minh Tinh Vực, nơi La Thiên và Tu Chân Liên Minh giao chiến kéo dài.","detail":"Bắc Bộ Liên Minh Tinh Vực là chiến trường giữa đại lượng tu sĩ La Thiên và lực lượng Tu Chân Liên Minh. Cuộc chiến đã kéo dài nửa năm, mùi máu tanh dày đặc; khi tiếng cười vô âm của Cổ Ma lan tới, cả Viêm Lôi Tử lẫn trưởng lão Liên Minh đang giao chiến đều chấn động kinh hãi.","theLucLienQuan":["La Thiên Tinh Vực","Tu Chân Liên Minh","Liên Minh Tu Chân"],"nguon":["@c0996"]},{"id":"tong-bo-lien-minh-tu-chan","name":"Tổng bộ Liên Minh Tu Chân","cn":"","capDo":"khac","parentId":"lien-minh-tu-chan-dia-vuc","blurb":"Tổng bộ của Liên Minh Tu Chân, nơi các tiên nhân cũ chuẩn bị tham chiến và cảm ứng biến cố Tiên Đế.","detail":"Tại tổng bộ Liên Minh Tu Chân, một số tiên nhân sống sót sau Tiên giới sụp đổ như Vương Nguy, Hồ Quyên vốn là lực lượng trung kiên đang chuẩn bị rời đi tham gia chiến loạn Bắc Bộ. Tiếng cười vô âm từ biến cố Thanh Sương khiến họ kinh hãi; sâu trong tổng bộ, một trung niên trong tinh cầu trên lốc xoáy cũng mở mắt vì cảm ứng đến Tiên Đế.","theLucLienQuan":["Liên Minh Tu Chân"],"nguon":["@c0996"]},{"id":"con-hu-chi-canh","name":"Côn Hư Chi Cảnh","cn":"","capDo":"khac","parentId":null,"blurb":"Địa vực nơi lão nhân Côn Hư và Côn Hư Thánh Nữ Mộc Băng Mi cảm ứng biến cố từ Yêu Linh Chi Địa.","detail":"Trong Côn Hư Chi Cảnh, lão nhân Côn Hư nhìn về phương hướng Yêu Linh Chi Địa và nhận ra có tồn tại đã tỉnh lại, nhưng lập tức phủ định đó là người hắn nghĩ tới. Mộc Băng Mi đứng bên cạnh cũng chứng kiến phản ứng này.","theLucLienQuan":["Côn Hư Chi Cảnh"],"nguon":["@c0996"]},{"id":"hoa-hai-tinh-vuc","name":"Hỏa Hải Tinh Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực có Chu Tước tông thuộc Tứ Thánh tông, được xem là cấm địa đối với Tu Chân Liên Minh.","detail":"Hỏa Hải Tinh Vực là địa bàn của Chu Tước tông trong Tứ Thánh tông. Tại nơi có căn nguyên hỏa hải, Chu Tước Thánh Hoàng tọa trấn trên một hòn đá và cảm ứng biến cố lớn, lo lắng cho cơ vận quật khởi của Chu Tước thánh tông.","theLucLienQuan":["Tứ Thánh tông","Chu Tước thánh tông"],"nguon":["@c0996"]},{"id":"cung-dien-sup-do-phia-truoc","name":"Cung điện sụp đổ phía trước","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Cung điện đổ nát trong động phủ Tiên Đế nơi Hồ Quyên hôn mê.","detail":"Vương Nguy chỉ Vương Lâm tới cung điện phía trước vì đó là nơi thê tử hắn ở. Vương Lâm dùng thần thức phát hiện Hồ Quyên hôn mê trong đống hoang tàn tại đây rồi đánh thức nàng.","theLucLienQuan":[],"nguon":["@c0997"]},{"id":"vu-gioi-ton-dien","name":"Vũ giới tôn điện","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Địa danh được Hồ Quyên truyền lại trong manh mối của Thanh Sương.","detail":"Hồ Quyên nói sư tôn trước khi mang nàng đi chỉ để lại câu “Vũ giới tôn điện, nguyên thần kết tinh, máu Thanh Sương”, khiến nơi này trở thành đích đến hoặc chìa khóa kế tiếp trong động phủ.","theLucLienQuan":["Thanh Sương"],"nguon":["@c0997"]},{"id":"mat-dat-chien-truong","name":"Mặt đất chiến trường","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Khu vực mặt đất bên dưới trận chiến, nơi hắc khí ma long rơi xuống và kiến trúc còn sót lại bị phá thành hoang tàn.","detail":"Trong lúc hắc khí ma long bị máu hậu nhân Thanh Sương khắc chế, nó rơi xuống mặt đất, khiến những kiến trúc còn sót lại bên dưới lập tức biến thành đống hoang tàn. Đây là không gian trực tiếp hứng chịu dư ba giao chiến giữa Vương Lâm, Cổ Ma và các tu sĩ khác.","theLucLienQuan":["Cổ Ma","Cổ chi nhất tộc"],"nguon":["@c0998"]},{"id":"tang-nam-tien-de-dong-phu","name":"Tầng năm tiên đế động phủ","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Một tầng trong động phủ Tiên Đế bị lốc lửa của Vương Lâm xông phá trong biến cố tầng thông tầng.","detail":"Tầng năm bị lốc lửa cuốn qua khi Vương Lâm sau lần dị biến hỏa lực phá liên tiếp các tầng động phủ. Vương Nguy vừa tỉnh lại cùng Hồ Quyên theo ngọn lửa lao lên, về sau phù văn do Bối La thi triển Yêu Linh Biến cũng bay nhanh xuống tầng này.","theLucLienQuan":[],"nguon":["@c0999"]},{"id":"tang-ba-tien-de-dong-phu","name":"Tầng ba tiên đế động phủ","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Một tầng trong chuỗi các tầng bị lốc lửa của Vương Lâm phá vỡ khi động phủ rung chuyển.","detail":"Tầng ba được nhắc trong quá trình lốc lửa từ tầng bảy phá dần lên các tầng phía trên, góp phần mở ra thông đạo liên tầng và đẩy động phủ Tiên Đế vào trạng thái sụp đổ dây chuyền.","theLucLienQuan":[],"nguon":["@c0999"]},{"id":"tang-mot-tien-de-dong-phu","name":"Tầng một tiên đế động phủ","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Nơi lốc lửa dừng lại, Vương Lâm hoàn thành trạng thái Chu Tước trắng thức tỉnh lần thứ hai và cùng mọi người phá mặt đất.","detail":"Tầng một là điểm lốc lửa phá lên sau khi xuyên qua nhiều tầng động phủ. Tại đây Vương Lâm đứng trong trạng thái tóc bạc, sau lưng hiện Chu Tước màu trắng, rồi cùng Hồ Quyên, Vương Nguy và Tư Đồ Nam oanh kích mặt đất, bố trí cấm chế để đối phó Cổ Ma Tháp Già trồi lên từ bên dưới.","theLucLienQuan":[],"nguon":["@c0999"]},{"id":"yeu-van-tinh-dong-hai-nhap-khau","name":"Yêu Vận Tinh / Đông Hải nhập khẩu","cn":"","capDo":"tinh-cau","parentId":"yeu-linh-chi-dia","blurb":"Cửa vào được nhắc tới khi Chu Tước chân linh tìm đường tiếp cận nơi tộc nhân thức tỉnh.","detail":"Yêu Vận Tinh và Đông Hải nhập khẩu được nhắc như cửa vào mà Chu Tước chân linh không chọn. Thay vì đi qua lối này, Chu Tước chân linh dẫn người Chu Tước Thánh Tông tìm một vùng bụi bặm trong Yêu Linh chi địa để cảm ứng vị trí thức tỉnh.","theLucLienQuan":["Chu Tước Thánh Tông"],"nguon":["@c0999"]},{"id":"tinh-vuc-chu-tuoc-thanh-tong-nhien-thieu-tinh-vuc","name":"Tinh vực Chu Tước Thánh Tông / Nhiên Thiêu tinh vực","cn":"","capDo":"vuc","parentId":"lien-minh-tinh-vuc","blurb":"Tinh vực của Chu Tước Thánh Tông, nơi Chu Tước Thánh Hoàng cảm ứng lần thức tỉnh thứ hai của Vương Lâm.","detail":"Tại tinh vực này, Chu Tước Thánh Hoàng cảm ứng được biến cố Chu Tước thức tỉnh lần thứ hai, nhận định đó là hy vọng quật khởi của Chu Tước Thánh Tông. Sự kiện khiến tinh vực rung chuyển và thúc đẩy nguyên thần của Thánh Hoàng rời đi.","theLucLienQuan":["Chu Tước Thánh Tông"],"nguon":["@c0999"]},{"id":"di-tich-co-chi-to-tien-map","name":"Di tích cổ chi tổ tiên","cn":"","capDo":"khac","parentId":null,"blurb":"Đích đến mà Cổ Ma Tháp Già nhắc tới sau khi đạt cửu tinh Cổ Ma chân chính.","detail":"Tháp Già nói sau khi hoàn toàn dung hợp thân thể Thanh Sương và đạt cửu tinh chân chính của Cổ Ma bộ tộc, hắn có thể tiến vào di tích cổ chi tổ tiên để lấy phản cổ chi lực chân chính. Địa danh này gắn với mục tiêu sâu xa của Tháp Già trong biến cố động phủ.","theLucLienQuan":["Cổ Ma bộ tộc","Cổ chi tam tộc"],"nguon":["@c0999"]},{"id":"ho-sau-tien-de-dong-phu","name":"Hố sâu","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Lối mở nguy hiểm trong động phủ, nơi nhiều tu sĩ lao ra và cũng là nơi Vương Lâm dẫn công kích đánh xuống.","detail":"Hố sâu là lối từ đó nhóm tu sĩ như Đại Dầu, Trần Đạo Tam Tử, Lôi Cát, Phù Trầm Tử và những người khác thoát ra. Về sau Vương Lâm thúc Chu Tước lao xuống hố, bản thân cùng Hồ Quyên và Tư Đồ Nam nhảy vào thi triển công kích mạnh để phá sập thông đạo động phủ.","theLucLienQuan":[],"nguon":["@c0999"]},{"id":"manh-dat-hoang-tan-tren-mat-dat-sup-xuong","name":"Mảnh đất hoang tàn trên mặt đất sụp xuống","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Khu vực mặt đất sụp lõm sau khi tầng thứ hai động phủ Tiên Đế bị đánh phá.","detail":"Sau khi thông đạo xuyên tầng bị đánh phá, mặt đất lõm xuống và biến thành một vùng hoang tàn. Vương Lâm, Hồ Quyên, Vương Nguy, Phù Trầm Tử và những tu sĩ biết cấm chế cùng bố trí lưới cấm chế trên khu vực này, rồi Vương Lâm dùng máu Thanh Ải thấm đẫm cấm chế để ngăn Cổ Ma Tháp Già.","theLucLienQuan":[],"nguon":["@c0999"]},{"id":"tinh-khong-ben-ngoai-yeu-linh-chi-dia","name":"Tinh không bên ngoài Yêu Linh Chi Địa","cn":"","capDo":"khac","parentId":"tinh-khong","blurb":"Khu vực tinh không nơi sáu tu sĩ Toái Niết và Chu Tước Chân Linh công kích phong ấn Yêu Linh Chi Địa.","detail":"Từ vị trí này, sáu tu sĩ Toái Niết của Chu Tước Thánh Tông phối hợp Chu Tước Chân Linh đốt bụi che thần thức và liên tục va vào phong ấn Thanh Sương.","theLucLienQuan":["Chu Tước Thánh Tông"],"nguon":["@c1000"]},{"id":"dau-co-than","name":"Đầu Cổ Thần","cn":"","capDo":"khac","parentId":null,"blurb":"Bối cảnh được nhắc như nơi chứa Táng Tiên Trì trong thân thể Cổ Thần.","detail":"Vương Lâm suy đoán vật hình người loại Vọng Nguyệt từng tiến vào Táng Tiên Trì bên trong đầu Cổ Thần sau quá trình Cổ Ma và Tiên Đế giằng co.","theLucLienQuan":["Cổ Thần"],"nguon":["@c1000"]},{"id":"dong-phu-cua-vuong-lam","name":"Động phủ của Vương Lâm","cn":"","capDo":"khac","parentId":null,"blurb":"Địa điểm được nhắc để ví hướng cung điện hư ảnh xoay chuyển như bay ra từ động phủ của Vương Lâm.","detail":"Trong chương, động phủ của Vương Lâm không phải chiến trường chính mà được dùng như mốc so sánh khi miêu tả hướng xoay chuyển của cung điện hư ảnh.","theLucLienQuan":["Vương Lâm"],"nguon":["@c1001"]},{"id":"thien-linh-tien-canh","name":"Thiên Linh Tiên Cảnh","cn":"","capDo":"khac","parentId":null,"blurb":"Thiên Linh Tiên Cảnh được nhắc trong lời Thanh Lâm lưu lại cho Hoa Phi. Khi nơi này tan vỡ, Hoa Phi liên hệ điều đó với hy vọng thức tỉnh nhờ người họ Vương.","detail":"Trong chương 1002, Hoa Phi nhớ đến lời Thanh Lâm năm xưa rằng người cứu hắn có họ Vương và thời điểm Thiên Linh Tiên Cảnh tan vỡ gắn với hy vọng thức tỉnh của nàng. Chi tiết này khiến Hoa Phi nhận ra lời lưu lại của Thanh Lâm đang ứng nghiệm giữa biến động trong tiên đế động phủ.","theLucLienQuan":[],"nguon":["@c1002"]},{"id":"bien-rong-trong-tan-da","name":"Biển rộng trong Tàn Dạ","cn":"","capDo":"khac","parentId":null,"blurb":"Cảnh tượng trong thần thông Tàn Dạ, nơi mặt trời trồi lên khỏi mặt biển để mở ra uy lực xé rách đêm tối.","detail":"Biển rộng là không gian biểu hiện của Tàn Dạ khi Vương Lâm thi triển thần thông. Sau khi mặt trời tự bạo và thiên địa trong thần thông sụp đổ, cảnh biển rộng cũng biến mất, để vùng đất Yêu Linh hiện lại.","theLucLienQuan":[],"nguon":["@c1004"]},{"id":"mat-troi-trong-tan-da","name":"Mặt trời trong Tàn Dạ","cn":"","capDo":"khac","parentId":"bien-rong-trong-tan-da","blurb":"Hình thái trung tâm của Tàn Dạ, bao quanh Vương Lâm và phát ra ánh sáng cùng sức nóng thiêu đốt đối thủ.","detail":"Mặt trời trong Tàn Dạ là nguồn ánh sáng xé rách đêm tối và là nơi Vương Lâm ẩn hiện khi triển khai thần thông. Khi bị huyết kiếm áo xám xuyên phá, Vương Lâm tự bạo vầng mặt trời ngoài thân để quét ngang chiến trường.","theLucLienQuan":[],"nguon":["@c1004"]},{"id":"noi-chua-menh-bai-cua-tu-chan-lien-minh","name":"Nơi chứa mệnh bài của Tu Chân Liên Minh","cn":"","capDo":"khac","parentId":"tong-bo-tu-chan-lien-minh","blurb":"Nơi chứa mệnh bài của Tu Chân Liên Minh nằm trong tổng bộ và đặt các mệnh bài cường giả trọng yếu. Tầng cao nhất có ba Tử ngọc linh bài, một trong số đó thuộc Hư Không Tử.","detail":"Khi Hư Không Tử tử vong, một Tử ngọc linh bài ở tầng cao nhất nơi chứa mệnh bài sụp đổ. Người đàn ông trung niên trong tổng bộ lập tức tới đây và nhìn thấy lệnh bài Hư Không Tử vỡ vụn.","theLucLienQuan":["Tu Chân Liên Minh"],"nguon":["@c1005"]},{"id":"vung-dat-pham-vi-tram-dam","name":"Vùng đất phạm vi trăm dặm","cn":"","capDo":"khac","parentId":"dong-phu-tien-de","blurb":"Vùng đất bị thần thông hỗn độn đen trắng của Thiên Vận Tử tác động trong trận quyết chiến. Nó nứt vỡ, bay lên như một cây cột lớn và bị sương mù đen trắng bao phủ.","detail":"Trong động phủ Tiên Đế, Thiên Vận Tử thi pháp khiến mặt đất phạm vi trăm dặm nứt vỡ rồi bay lên không như một cây cột lớn lao vào hỗn độn đen trắng trên trời. Xung quanh vùng đất bị sương mù đen trắng che phủ, ánh mắt và thần thức đều khó xuyên thấu.","theLucLienQuan":["Thiên Vận Tử","Chu Tước Thánh tông","Cổ Ma Tháp Già"],"nguon":["@c1006"]},{"id":"hon-don-den-trang-ngoai-tram-dam","name":"Hỗn độn đen trắng ngoài trăm dặm","cn":"","capDo":"khac","parentId":"vung-dat-pham-vi-tram-dam","blurb":"Vùng hỗn độn đen trắng bao quanh chiến trường ngoài trăm dặm. Đây là nơi Thiên Vận Tử gọi ra nhiều sinh linh và cũng bị Thiên Lôi xuyên phá.","detail":"Hỗn độn đen trắng ngoài trăm dặm là môi trường mà Thiên Vận Tử dùng để gọi người không đầu, hắc mãng, kỳ lân hư thối và thêm năm người không đầu ra công kích Vương Lâm. Khi nguyên thần Thái Cổ Lôi Long rít lên, từng đạo Thiên Lôi phá qua hỗn độn này để đánh tan hắc mãng.","theLucLienQuan":["Thiên Vận Tử"],"nguon":["@c1007"]}]};
